export interface PaymentSessionResponse {
  success: boolean;
  transactionId?: string;
  checkoutUrl?: string;
  message: string;
}

export const paymentService = {
  /**
   * Simulates initiating a payment with a third-party API
   */
  initiateAutomatedPayment: async (
    methodId: string,
    amount: number,
    config: { 
      publicKey?: string; 
      merchantId?: string; 
      type: 'bank' | 'crypto' 
    }
  ): Promise<PaymentSessionResponse> => {
    // Simulate API network delay
    await new Promise(resolve => setTimeout(resolve, 2000));

    if (!config.publicKey || !config.merchantId) {
      return {
        success: false,
        message: "API Configuration missing. Please contact the administrator to set up Public Key and Merchant ID."
      };
    }

    // Mock validation logic
    if (amount <= 0) {
      return { success: false, message: "Invalid amount." };
    }

    return {
      success: true,
      transactionId: `TXN-${Math.random().toString(36).substr(2, 9).toUpperCase()}`,
      checkoutUrl: `https://checkout.nettoolz.com/pay/${methodId}`,
      message: "Payment session generated successfully."
    };
  },

  /**
   * Simulates the webhook/callback that confirms payment
   */
  verifyPayment: async (transactionId: string): Promise<boolean> => {
    await new Promise(resolve => setTimeout(resolve, 1500));
    // In a real app, this would query the gateway status
    return true; 
  }
};

import React, { useState } from 'react';
import { SiteSettings } from '../types';
import { paymentService } from '../services/paymentService';

interface WalletFundingProps {
  settings: SiteSettings;
  onBack: () => void;
  onFundSuccess: (amount: number) => void;
}

const WalletFunding: React.FC<WalletFundingProps> = ({ settings, onBack, onFundSuccess }) => {
  const activeMethods = settings.paymentMethods.filter(m => m.isActive);
  const [usdtAmount, setUsdtAmount] = useState<string>('10');
  const [isProcessing, setIsProcessing] = useState<string | null>(null);
  const [paymentSuccess, setPaymentSuccess] = useState<{amount: number, id: string} | null>(null);

  const nairaValue = parseFloat(usdtAmount || '0') * settings.usdtToNairaRate;

  const handleAutomatedPayment = async (method: any) => {
    setIsProcessing(method.id);

    const response = await paymentService.initiateAutomatedPayment(
      method.id,
      nairaValue,
      { 
        publicKey: method.apiPublicKey, 
        merchantId: method.merchantId,
        type: method.type 
      }
    );

    if (response.success) {
      // Simulate user completing the payment on the checkout page
      await new Promise(resolve => setTimeout(resolve, 3000));
      const verified = await paymentService.verifyPayment(response.transactionId!);

      if (verified) {
        setPaymentSuccess({ amount: nairaValue, id: response.transactionId! });
        onFundSuccess(nairaValue);
      }
    } else {
      alert(response.message);
    }

    setIsProcessing(null);
  };

  if (paymentSuccess) {
    return (
      <div className="max-w-xl mx-auto py-20 text-center animate-in zoom-in-95 duration-500">
        <div className="w-24 h-24 bg-green-100 dark:bg-green-900/30 text-green-500 rounded-full flex items-center justify-center text-5xl mx-auto mb-8 shadow-xl shadow-green-100 dark:shadow-none">
          <i className="fa-solid fa-check-double"></i>
        </div>
        <h2 className="text-4xl font-black text-slate-900 dark:text-white mb-4">Payment Confirmed!</h2>
        <p className="text-slate-500 dark:text-slate-400 mb-8 font-medium">
          Transaction <span className="text-sky-500 font-mono font-bold">{paymentSuccess.id}</span> was successful. 
          Your wallet has been credited with <span className="text-slate-900 dark:text-white font-black">₦{paymentSuccess.amount.toLocaleString()}</span>.
        </p>
        <button 
          onClick={onBack}
          className="bg-sky-500 hover:bg-sky-600 text-white font-black px-12 py-4 rounded-2xl shadow-lg transition-all active:scale-95"
        >
          Return to Profile
        </button>
      </div>
    );
  }

  return (
    <div className="max-w-4xl mx-auto py-12 px-4 transition-colors">
      <button onClick={onBack} className="mb-8 font-black text-sky-500 flex items-center hover:underline">
        <i className="fa-solid fa-arrow-left mr-2"></i> Back to Profile
      </button>

      <div className="text-center mb-12">
        <h2 className="text-4xl font-black text-slate-800 dark:text-white">Fund Your Account</h2>
        <p className="text-slate-500 dark:text-slate-400 mt-2">Current Conversion Rate: <span className="font-bold text-sky-600 dark:text-sky-400">1 USDT = {settings.currencySymbol}{settings.usdtToNairaRate.toLocaleString()}</span></p>
      </div>

      <div className="grid grid-cols-1 gap-8">
        {activeMethods.length === 0 ? (
          <div className="bg-white dark:bg-slate-900 p-12 rounded-3xl border border-sky-100 dark:border-slate-800 text-center transition-colors">
            <p className="text-slate-500 dark:text-slate-400">No payment methods currently active. Please contact support.</p>
          </div>
        ) : (
          activeMethods.map(method => (
            <div key={method.id} className="bg-white dark:bg-slate-900 p-8 rounded-3xl border border-sky-100 dark:border-slate-800 shadow-sm flex flex-col md:flex-row gap-8 transition-all hover:border-sky-300 dark:hover:border-sky-700">
              <div className="bg-sky-50 dark:bg-slate-950 w-20 h-20 rounded-2xl flex items-center justify-center text-sky-500 dark:text-sky-400 text-3xl shrink-0 transition-colors">
                <i className={`fa-solid ${method.type === 'bank' ? 'fa-building-columns' : 'fa-coins'}`}></i>
              </div>
              <div className="flex-1">
                <div className="flex flex-col sm:flex-row sm:items-center justify-between mb-4">
                   <h3 className="text-2xl font-black text-slate-800 dark:text-white">{method.name}</h3>
                   {method.isAutomated && (
                     <span className="inline-block bg-sky-500 text-white text-[10px] font-black px-3 py-1 rounded-full mt-2 sm:mt-0 tracking-widest animate-pulse shadow-lg shadow-sky-200">
                       <i className="fa-solid fa-bolt mr-1"></i> INSTANT FUNDING
                     </span>
                   )}
                </div>

                <div className="bg-slate-50 dark:bg-slate-950/50 rounded-2xl p-6 border border-slate-100 dark:border-slate-800 space-y-4 transition-colors">
                  {method.isAutomated ? (
                    <div className="space-y-6">
                      <div className="flex items-center space-x-3 bg-white dark:bg-slate-900 p-4 rounded-2xl border border-sky-100 dark:border-slate-800 shadow-sm transition-colors">
                        <div className="flex-1">
                          <label className="text-[10px] font-bold text-slate-400 dark:text-slate-500 uppercase">USDT Amount</label>
                          <input 
                            type="number" 
                            value={usdtAmount}
                            onChange={(e) => setUsdtAmount(e.target.value)}
                            className="w-full text-xl font-black bg-transparent dark:text-white focus:outline-none"
                            placeholder="0.00"
                          />
                        </div>
                        <div className="text-sky-300 dark:text-sky-800"><i className="fa-solid fa-right-long"></i></div>
                        <div className="flex-1 text-right">
                          <label className="text-[10px] font-bold text-slate-400 dark:text-slate-500 uppercase">Will Receive (NGN)</label>
                          <p className="text-xl font-black text-sky-600 dark:text-sky-400">₦{nairaValue.toLocaleString()}</p>
                        </div>
                      </div>

                      <button 
                        onClick={() => handleAutomatedPayment(method)}
                        disabled={!!isProcessing}
                        className="w-full bg-sky-500 hover:bg-sky-600 disabled:bg-sky-300 text-white font-black py-4 rounded-2xl shadow-lg transition-all active:scale-95 flex items-center justify-center space-x-3"
                      >
                        {isProcessing === method.id ? (
                          <>
                            <i className="fa-solid fa-spinner animate-spin"></i>
                            <span>Connecting to Gateway...</span>
                          </>
                        ) : (
                          <>
                            <i className="fa-solid fa-credit-card"></i>
                            <span>Proceed to Instant Pay</span>
                          </>
                        )}
                      </button>
                    </div>
                  ) : (
                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                      {method.type === 'bank' ? (
                        <>
                          <div>
                            <p className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest mb-1">Bank Name</p>
                            <p className="font-bold text-slate-800 dark:text-slate-200">{method.bankName}</p>
                          </div>
                          <div>
                            <p className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest mb-1">Account Number</p>
                            <div className="flex items-center space-x-2">
                              <p className="font-black text-xl text-sky-600 dark:text-sky-400 tracking-wider">{method.accountNumber}</p>
                              <button onClick={() => { navigator.clipboard.writeText(method.accountNumber || ''); alert('Copied!'); }} className="text-slate-300 hover:text-sky-500"><i className="fa-solid fa-copy"></i></button>
                            </div>
                          </div>
                        </>
                      ) : (
                        <div className="col-span-full">
                          <p className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest mb-1">Wallet Address ({method.network})</p>
                          <div className="flex items-center space-x-2 bg-white dark:bg-slate-900 p-3 rounded-xl border border-sky-50 dark:border-slate-800">
                            <p className="font-mono text-sm text-sky-700 dark:text-sky-400 break-all">{method.walletAddress}</p>
                            <button onClick={() => { navigator.clipboard.writeText(method.walletAddress || ''); alert('Copied!'); }} className="text-slate-300 hover:text-sky-500 shrink-0"><i className="fa-solid fa-copy"></i></button>
                          </div>
                        </div>
                      )}
                    </div>
                  )}

                  <div className="pt-4 mt-4 border-t border-slate-200 dark:border-slate-800">
                    <p className="text-slate-600 dark:text-slate-400 text-xs font-medium italic">{method.details}</p>
                  </div>
                </div>

                {!method.isAutomated && (
                  <div className="mt-6 flex items-center space-x-3 text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-900/10 p-4 rounded-xl border border-sky-100 dark:border-sky-800">
                    <i className="fa-solid fa-message-dots text-xl"></i>
                    <p className="text-xs font-bold uppercase tracking-tight">Manual Confirmation: After payment, send proof to support on Telegram.</p>
                  </div>
                )}
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

export default WalletFunding;

import React, { useState, useEffect } from 'react';
import { Product, CartItem, ViewState, Category, SiteSettings, AdminUser, User, UserOrder } from './types';
import { INITIAL_PRODUCTS, CATEGORIES } from './constants';
import Navbar from './components/Navbar';
import ProductCard from './components/ProductCard';
import GeminiAssistant from './components/GeminiAssistant';
import AdminLogin from './components/AdminLogin';
import AdminDashboard from './components/AdminDashboard';
import UserAuth from './components/UserAuth';
import UserProfile from './components/UserProfile';
import WalletFunding from './components/WalletFunding';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewState>('home');
  const [selectedCategory, setSelectedCategory] = useState<string | null>(null);
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [isProcessingCheckout, setIsProcessingCheckout] = useState(false);

  // Admin & Settings State
  const [products, setProducts] = useState<Product[]>(INITIAL_PRODUCTS);
  const [admins, setAdmins] = useState<AdminUser[]>([
    { id: '1', username: 'Admin', role: 'super' }
  ]);
  const [settings, setSettings] = useState<SiteSettings>({
    currency: 'NGN',
    currencySymbol: '₦',
    storeName: 'NETTOOLZ',
    usdtToNairaRate: 1650, 
    paymentMethods: [
      { 
        id: 'bank1', 
        type: 'bank', 
        name: 'KoralPay (Automated Bank)', 
        details: 'Transfer to the virtual account generated at checkout.', 
        isActive: true,
        isAutomated: true,
        apiPublicKey: 'pk_live_nettoolz_7721',
        merchantId: 'MER-88122'
      },
      { 
        id: 'crypto1', 
        type: 'crypto', 
        name: 'Crypto (Instant Credit)', 
        details: 'Payment credits after 1 network confirmation.', 
        walletAddress: 'TYxxxxxxxxxxxxxxxxxxxxxx',
        network: 'TRC20',
        isActive: true,
        isAutomated: true,
        apiPublicKey: 'pk_live_crypto_9921',
        merchantId: 'MER-99123'
      }
    ]
  });
  const [isAdminLoggedIn, setIsAdminLoggedIn] = useState(false);

  // User State
  const [users, setUsers] = useState<User[]>([]);
  const [currentUser, setCurrentUser] = useState<User | null>(null);

  // Persistence logic...
  useEffect(() => {
    const savedProducts = localStorage.getItem('nettoolz_products');
    if (savedProducts) setProducts(JSON.parse(savedProducts));
    const savedAdmin = localStorage.getItem('nettoolz_admin_logged');
    if (savedAdmin === 'true') setIsAdminLoggedIn(true);
    const savedUsers = localStorage.getItem('nettoolz_users');
    if (savedUsers) setUsers(JSON.parse(savedUsers));
    const savedSettings = localStorage.getItem('nettoolz_settings');
    if (savedSettings) setSettings(JSON.parse(savedSettings));
    const loggedUserEmail = localStorage.getItem('nettoolz_logged_user_email');
    if (loggedUserEmail && savedUsers) {
      const found = JSON.parse(savedUsers).find((u: User) => u.email === loggedUserEmail);
      if (found) setCurrentUser(found);
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('nettoolz_products', JSON.stringify(products));
    localStorage.setItem('nettoolz_users', JSON.stringify(users));
    localStorage.setItem('nettoolz_settings', JSON.stringify(settings));
    if (currentUser) localStorage.setItem('nettoolz_logged_user_email', currentUser.email);
    else localStorage.removeItem('nettoolz_logged_user_email');
  }, [products, users, currentUser, settings]);

  // Funding Logic
  const handleFundSuccess = (amount: number) => {
    if (!currentUser) return;
    const updatedUser = {
      ...currentUser,
      balance: currentUser.balance + amount
    };
    setUsers(prev => prev.map(u => u.email === updatedUser.email ? updatedUser : u));
    setCurrentUser(updatedUser);
  };

  const addToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      return [...prev, { ...product, quantity: 1 }];
    });
  };

  const handleCheckout = async () => {
    if (!currentUser) { setCurrentView('user_auth'); setIsCartOpen(false); return; }
    const total = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0);
    if (currentUser.balance < total) { alert('Insufficient balance.'); setCurrentView('fund_wallet'); setIsCartOpen(false); return; }

    setIsProcessingCheckout(true);
    await new Promise(resolve => setTimeout(resolve, 1500));
    const newOrders: UserOrder[] = cart.map(item => ({ id: Date.now().toString() + Math.random(), productId: item.id, productName: item.name, content: item.secretContent || 'Processing...', price: item.price, timestamp: Date.now() }));
    const updatedUser = { ...currentUser, balance: currentUser.balance - total, orders: [...currentUser.orders, ...newOrders] };
    setUsers(prev => prev.map(u => u.email === updatedUser.email ? updatedUser : u));
    setCurrentUser(updatedUser);
    setCart([]); setIsCartOpen(false); setIsProcessingCheckout(false); setCurrentView('profile');
    alert('Purchase confirmed!');
  };

  return (
    <div className="min-h-screen flex flex-col bg-sky-50 dark:bg-slate-950 transition-colors">
      <Navbar cartCount={cart.reduce((acc, item) => acc + item.quantity, 0)} isDarkMode={isDarkMode} onNavigate={setCurrentView} onOpenCart={() => setIsCartOpen(true)} onToggleTheme={() => { setIsDarkMode(!isDarkMode); document.documentElement.classList.toggle('dark'); }} />
      <main className="flex-1 max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 w-full">
        {currentView === 'home' && (
          <div className="space-y-16 py-12">
            <section className="relative px-6 py-20 bg-white dark:bg-slate-900 rounded-3xl border border-sky-100 dark:border-slate-800 overflow-hidden shadow-sm">
              <div className="relative z-10 text-center max-w-3xl mx-auto">
                <span className="inline-block px-4 py-2 bg-sky-100 dark:bg-sky-900/30 text-sky-600 dark:text-sky-400 rounded-full text-xs font-black uppercase mb-6 tracking-widest">Premium Digital Tools</span>
                <h1 className="text-5xl sm:text-6xl font-black text-slate-900 dark:text-white leading-tight mb-6">NET<span className="text-sky-500">TOOLZ</span> Enterprise</h1>
                <p className="text-lg text-slate-500 dark:text-slate-400 mb-10 leading-relaxed">Secure, automated access to high-performance proxies and VPNs.</p>
                <button onClick={() => setCurrentView('category')} className="bg-sky-500 hover:bg-sky-600 text-white font-bold px-10 py-4 rounded-2xl shadow-xl transition-all">Enter Catalog</button>
              </div>
            </section>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-8">
              {products.filter(p => p.isVisible).slice(0, 3).map(p => <ProductCard key={p.id} product={p} onAddToCart={addToCart} onViewDetails={(p) => { setSelectedProduct(p); setCurrentView('product'); }} />)}
            </div>
          </div>
        )}

        {currentView === 'category' && (
          <div className="py-12 flex flex-col md:flex-row gap-12">
            <div className="w-full md:w-64 space-y-4">
              <h3 className="text-lg font-black dark:text-white">Categories</h3>
              <div className="space-y-2">
                <button onClick={() => setSelectedCategory(null)} className={`w-full text-left px-4 py-2 rounded-xl ${!selectedCategory ? 'bg-sky-500 text-white font-bold' : 'bg-white dark:bg-slate-900 text-slate-400'}`}>All Assets</button>
                {CATEGORIES.map(cat => <button key={cat.id} onClick={() => setSelectedCategory(cat.id)} className={`w-full text-left px-4 py-2 rounded-xl ${selectedCategory === cat.id ? 'bg-sky-500 text-white font-bold' : 'bg-white dark:bg-slate-900 text-slate-400'}`}>{cat.name}</button>)}
              </div>
            </div>
            <div className="flex-1 grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
              {products.filter(p => p.isVisible && (!selectedCategory || p.category === selectedCategory)).map(p => <ProductCard key={p.id} product={p} onAddToCart={addToCart} onViewDetails={(p) => { setSelectedProduct(p); setCurrentView('product'); }} />)}
            </div>
          </div>
        )}

        {currentView === 'product' && selectedProduct && (
          <div className="py-12 max-w-5xl mx-auto">
            <div className="bg-white dark:bg-slate-900 rounded-3xl p-8 border border-sky-100 dark:border-slate-800 flex flex-col md:flex-row gap-12">
              <div className="flex-1 rounded-2xl overflow-hidden shadow-lg"><img src={selectedProduct.image} className="w-full h-full object-cover" /></div>
              <div className="flex-1 space-y-6">
                <h1 className="text-4xl font-black dark:text-white">{selectedProduct.name}</h1>
                <p className="text-3xl font-black text-sky-500">₦{selectedProduct.price.toLocaleString()}</p>
                <p className="text-slate-500 dark:text-slate-400">{selectedProduct.description}</p>
                <button onClick={() => addToCart(selectedProduct)} className="w-full bg-sky-500 text-white font-black py-4 rounded-xl shadow-lg">Add to Cart</button>
              </div>
            </div>
          </div>
        )}

        {currentView === 'user_auth' && <UserAuth users={users} onAuth={(u) => { setUsers([...users.filter(x => x.email !== u.email), u]); setCurrentUser(u); setCurrentView('profile'); }} onCancel={() => setCurrentView('home')} />}
        {currentView === 'profile' && currentUser && <UserProfile user={currentUser} settings={settings} onFundWallet={() => setCurrentView('fund_wallet')} onLogout={() => { setCurrentUser(null); setCurrentView('home'); }} />}
        {currentView === 'fund_wallet' && <WalletFunding settings={settings} onBack={() => setCurrentView('profile')} onFundSuccess={handleFundSuccess} />}
        {currentView === 'admin_dashboard' && isAdminLoggedIn && <AdminDashboard products={products} settings={settings} admins={admins} onUpdateProducts={setProducts} onUpdateSettings={setSettings} onUpdateAdmins={setAdmins} onLogout={() => { setIsAdminLoggedIn(false); setCurrentView('home'); }} />}
        {currentView === 'admin_login' && <AdminLogin onLogin={(s) => { if(s) { setIsAdminLoggedIn(true); setCurrentView('admin_dashboard'); } }} onCancel={() => setCurrentView('home')} />}
      </main>

      {/* Cart Drawer */}
      {isCartOpen && (
        <div className="fixed inset-0 z-[110] flex justify-end">
          <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={() => setIsCartOpen(false)}></div>
          <div className="relative w-full max-w-md bg-white dark:bg-slate-900 h-full p-8 flex flex-col">
            <h2 className="text-2xl font-black dark:text-white mb-8">Cart</h2>
            <div className="flex-1 overflow-y-auto space-y-4">
              {cart.map(item => (
                <div key={item.id} className="flex gap-4 p-4 bg-sky-50 dark:bg-slate-800 rounded-xl">
                  <div className="flex-1">
                    <p className="font-bold dark:text-white">{item.name}</p>
                    <p className="text-sky-500 font-bold">₦{item.price.toLocaleString()} x {item.quantity}</p>
                  </div>
                  <button onClick={() => setCart(cart.filter(i => i.id !== item.id))} className="text-red-400"><i className="fa-solid fa-trash"></i></button>
                </div>
              ))}
            </div>
            <div className="pt-8 border-t dark:border-slate-800 mt-6">
              <div className="flex justify-between text-2xl font-black mb-6 dark:text-white"><span>Total</span><span className="text-sky-500">₦{cart.reduce((a, i) => a + (i.price * i.quantity), 0).toLocaleString()}</span></div>
              <button onClick={handleCheckout} disabled={isProcessingCheckout || cart.length === 0} className="w-full bg-sky-500 text-white font-black py-4 rounded-xl">{isProcessingCheckout ? 'Processing...' : 'Complete Checkout'}</button>
            </div>
          </div>
        </div>
      )}

      <footer className="bg-white dark:bg-slate-900 border-t py-12 text-center">
        <p className="text-slate-400 text-xs font-black uppercase tracking-widest">© 2024 NETTOOLZ. Secure Digital Assets.</p>
        <button onClick={() => setCurrentView('admin_login')} className="mt-8 text-[10px] text-slate-300 hover:text-sky-500 font-black tracking-widest">ADMIN PORTAL</button>
      </footer>
      <GeminiAssistant />
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Product, Category, SiteSettings, AdminUser, PaymentMethod } from '../types';
import { CATEGORIES } from '../constants';
import { paymentService } from '../services/paymentService';

interface AdminDashboardProps {
  products: Product[];
  settings: SiteSettings;
  admins: AdminUser[];
  onUpdateProducts: (newProducts: Product[]) => void;
  onUpdateSettings: (newSettings: SiteSettings) => void;
  onUpdateAdmins: (newAdmins: AdminUser[]) => void;
  onLogout: () => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ 
  products, settings, admins, onUpdateProducts, onUpdateSettings, onUpdateAdmins, onLogout 
}) => {
  const [activeTab, setActiveTab] = useState<'products' | 'settings' | 'admins' | 'payments'>('products');
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [editingPayment, setEditingPayment] = useState<PaymentMethod | null>(null);
  const [isTestingApi, setIsTestingApi] = useState(false);
  const [apiTestResult, setApiTestResult] = useState<string | null>(null);
  const [showSecret, setShowSecret] = useState(false);

  const testApiConnection = async () => {
    if (!editingPayment) return;
    setIsTestingApi(true);
    setApiTestResult(null);

    // Simulate API handshake
    const res = await paymentService.initiateAutomatedPayment(
      'test', 
      1000, 
      { 
        publicKey: editingPayment.apiPublicKey, 
        merchantId: editingPayment.merchantId,
        type: editingPayment.type
      }
    );

    setApiTestResult(res.success ? "Connection Stable: API responded with 200 OK." : `Error: ${res.message}`);
    setIsTestingApi(false);
  };

  const handleSavePayment = (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingPayment) return;
    const existingIndex = settings.paymentMethods.findIndex(m => m.id === editingPayment.id);
    let newMethods;
    if (existingIndex > -1) {
      newMethods = settings.paymentMethods.map(m => m.id === editingPayment.id ? editingPayment : m);
    } else {
      newMethods = [...settings.paymentMethods, editingPayment];
    }
    onUpdateSettings({ ...settings, paymentMethods: newMethods });
    setEditingPayment(null);
    setApiTestResult(null);
  };

  return (
    <div className="flex flex-col md:flex-row min-h-[80vh] bg-white dark:bg-slate-900 rounded-3xl border border-sky-100 dark:border-slate-800 overflow-hidden shadow-xl mb-12">
      <div className="w-full md:w-64 bg-slate-900 text-white p-8">
        <h2 className="text-xl font-black mb-10 flex items-center space-x-2">
          <span className="bg-sky-500 p-1.5 rounded-lg"><i className="fa-solid fa-shield-halved"></i></span>
          <span>NETTOOLZ Admin</span>
        </h2>
        <nav className="space-y-2">
          <button onClick={() => setActiveTab('products')} className={`w-full text-left px-4 py-3 rounded-xl font-bold flex items-center space-x-3 ${activeTab === 'products' ? 'bg-sky-500' : 'text-slate-400 hover:bg-slate-800'}`}>
            <i className="fa-solid fa-box"></i><span>Inventory</span>
          </button>
          <button onClick={() => setActiveTab('payments')} className={`w-full text-left px-4 py-3 rounded-xl font-bold flex items-center space-x-3 ${activeTab === 'payments' ? 'bg-sky-500' : 'text-slate-400 hover:bg-slate-800'}`}>
            <i className="fa-solid fa-plug"></i><span>API Config</span>
          </button>
          <button onClick={() => setActiveTab('settings')} className={`w-full text-left px-4 py-3 rounded-xl font-bold flex items-center space-x-3 ${activeTab === 'settings' ? 'bg-sky-500' : 'text-slate-400 hover:bg-slate-800'}`}>
            <i className="fa-solid fa-gears"></i><span>General</span>
          </button>
        </nav>
        <button onClick={onLogout} className="mt-20 w-full text-left px-4 py-3 text-red-400 font-bold hover:bg-red-500/10 rounded-xl">
          <i className="fa-solid fa-power-off mr-2"></i>Logout
        </button>
      </div>

      <div className="flex-1 p-8 bg-sky-50/20 dark:bg-slate-900/40">
        <header className="flex justify-between items-center mb-10">
          <h3 className="text-3xl font-black dark:text-white capitalize">{activeTab}</h3>
          {activeTab === 'payments' && (
            <button 
              onClick={() => setEditingPayment({ id: Date.now().toString(), type: 'bank', name: 'New API Gateway', details: '', isActive: true, isAutomated: true })}
              className="bg-sky-500 text-white font-black px-6 py-2 rounded-xl shadow-lg"
            >
              Add New API
            </button>
          )}
        </header>

        {activeTab === 'payments' && (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {settings.paymentMethods.map(method => (
              <div key={method.id} className="bg-white dark:bg-slate-800 p-6 rounded-2xl border border-sky-100 dark:border-slate-700 shadow-sm relative group">
                <div className="flex justify-between items-start mb-4">
                   <div className="bg-sky-50 dark:bg-slate-900 w-12 h-12 rounded-xl flex items-center justify-center text-sky-500 text-xl">
                      <i className={`fa-solid ${method.isAutomated ? 'fa-bolt' : 'fa-building-columns'}`}></i>
                   </div>
                   <div className="flex space-x-2">
                     <button onClick={() => setEditingPayment(method)} className="text-sky-500"><i className="fa-solid fa-pen-to-square"></i></button>
                   </div>
                </div>
                <h4 className="font-black text-lg dark:text-white">{method.name}</h4>
                <p className="text-xs text-slate-400 font-bold uppercase tracking-widest mt-1">
                  {method.isAutomated ? 'Automated Gateway' : 'Manual Transfer'}
                </p>
                <div className="mt-4 flex items-center justify-between">
                   <span className={`px-2 py-1 rounded text-[10px] font-black ${method.isActive ? 'bg-green-100 text-green-600' : 'bg-slate-100 text-slate-400'}`}>
                      {method.isActive ? 'ACTIVE' : 'DISABLED'}
                   </span>
                </div>
              </div>
            ))}
          </div>
        )}

        {activeTab === 'products' && (
          <div className="bg-white dark:bg-slate-800 rounded-2xl border overflow-hidden shadow-sm">
            <table className="w-full text-left">
              <thead className="bg-sky-50 dark:bg-slate-900/50 text-slate-400 text-[10px] font-black uppercase tracking-widest">
                <tr><th className="px-6 py-4">Item</th><th className="px-6 py-4">Price</th><th className="px-6 py-4">Stock</th><th className="px-6 py-4">Action</th></tr>
              </thead>
              <tbody className="text-sm dark:text-slate-300">
                {products.map(p => (
                  <tr key={p.id} className="border-t border-sky-50 dark:border-slate-700">
                    <td className="px-6 py-4 font-bold">{p.name}</td>
                    <td className="px-6 py-4">₦{p.price.toLocaleString()}</td>
                    <td className="px-6 py-4">{p.stock}</td>
                    <td className="px-6 py-4"><button onClick={() => setEditingProduct(p)} className="text-sky-500 font-bold">Edit</button></td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>

      {/* API Config Modal */}
      {editingPayment && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-900/80 backdrop-blur-sm" onClick={() => setEditingPayment(null)}></div>
          <div className="relative bg-white dark:bg-slate-900 w-full max-w-xl rounded-3xl shadow-2xl p-8 border border-sky-200">
             <h3 className="text-2xl font-black mb-6 dark:text-white">API Configuration</h3>
             <form onSubmit={handleSavePayment} className="space-y-5">
                <div>
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1 block">Account Label</label>
                  <input type="text" value={editingPayment.name} onChange={e => setEditingPayment({...editingPayment, name: e.target.value})} className="w-full bg-sky-50 dark:bg-slate-800 p-3 rounded-xl border border-sky-100 dark:border-slate-700 dark:text-white" required />
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <label className="flex items-center space-x-3 cursor-pointer p-3 rounded-xl border border-sky-100 bg-sky-50 dark:bg-slate-800">
                    <input type="checkbox" checked={editingPayment.isAutomated} onChange={e => setEditingPayment({...editingPayment, isAutomated: e.target.checked})} className="w-4 h-4 text-sky-500" />
                    <span className="text-sm font-black dark:text-white uppercase tracking-tighter">Enable API Integration</span>
                  </label>
                </div>

                {editingPayment.isAutomated && (
                  <div className="space-y-4 animate-in fade-in slide-in-from-top-2">
                     <div className="p-4 bg-sky-500/5 rounded-2xl border border-sky-500/20 space-y-4">
                        <div>
                          <label className="text-[10px] font-black text-sky-500 uppercase block mb-1">API Public Key</label>
                          <input type="text" value={editingPayment.apiPublicKey || ''} onChange={e => setEditingPayment({...editingPayment, apiPublicKey: e.target.value})} className="w-full bg-white dark:bg-slate-900 p-2 rounded-lg border border-sky-100 font-mono text-xs dark:text-white" placeholder="pk_live_..." />
                        </div>
                        <div>
                          <label className="text-[10px] font-black text-sky-500 uppercase block mb-1">API Secret Key</label>
                          <div className="relative">
                            <input type={showSecret ? "text" : "password"} value={editingPayment.apiSecretKey || ''} onChange={e => setEditingPayment({...editingPayment, apiSecretKey: e.target.value})} className="w-full bg-white dark:bg-slate-900 p-2 rounded-lg border border-sky-100 font-mono text-xs dark:text-white" placeholder="sk_live_..." />
                            <button type="button" onClick={() => setShowSecret(!showSecret)} className="absolute right-2 top-1.5 text-slate-300 hover:text-sky-500 transition-colors"><i className={`fa-solid ${showSecret ? 'fa-eye-slash' : 'fa-eye'}`}></i></button>
                          </div>
                        </div>
                        <div>
                          <label className="text-[10px] font-black text-sky-500 uppercase block mb-1">Merchant ID</label>
                          <input type="text" value={editingPayment.merchantId || ''} onChange={e => setEditingPayment({...editingPayment, merchantId: e.target.value})} className="w-full bg-white dark:bg-slate-900 p-2 rounded-lg border border-sky-100 font-mono text-xs dark:text-white" placeholder="MER-..." />
                        </div>

                        <div className="pt-2">
                           <button 
                            type="button" 
                            onClick={testApiConnection}
                            disabled={isTestingApi}
                            className="w-full py-2 bg-slate-900 text-white text-[10px] font-black rounded-lg hover:bg-black transition-all flex items-center justify-center space-x-2"
                           >
                             {isTestingApi ? <i className="fa-solid fa-spinner animate-spin"></i> : <i className="fa-solid fa-vial"></i>}
                             <span>{isTestingApi ? 'TESTING...' : 'RUN CONNECTIVITY TEST'}</span>
                           </button>
                           {apiTestResult && (
                             <p className={`mt-2 text-[10px] font-bold text-center ${apiTestResult.includes('Stable') ? 'text-green-500' : 'text-red-500'}`}>
                               {apiTestResult}
                             </p>
                           )}
                        </div>
                     </div>
                  </div>
                )}

                <div className="flex justify-end space-x-3 pt-6">
                  <button type="button" onClick={() => setEditingPayment(null)} className="px-6 py-2 text-slate-400 font-bold uppercase tracking-widest text-xs hover:text-slate-600 transition-colors">Cancel</button>
                  <button type="submit" className="px-8 py-3 bg-sky-500 text-white font-black rounded-xl shadow-lg shadow-sky-100">Save Changes</button>
                </div>
             </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminDashboard;

export interface Product {
  id: string;
  name: string;
  description: string;
  price: number;
  category: string;
  stock: number;
  rating: number;
  image: string;
  features: string[];
  isVisible: boolean;
  secretContent: string;
}

export interface CartItem extends Product {
  quantity: number;
}

export interface Category {
  id: string;
  name: string;
  icon: string;
}

export interface PaymentMethod {
  id: string;
  type: 'bank' | 'crypto';
  name: string;
  details: string;
  isActive: boolean;
  bankName?: string;
  accountNumber?: string;
  accountName?: string;
  walletAddress?: string;
  network?: string;
  // API Configuration
  isAutomated: boolean;
  apiPublicKey?: string;
  apiSecretKey?: string;
  merchantId?: string;
  webhookUrl?: string;
}

export interface SiteSettings {
  currency: string;
  currencySymbol: string;
  storeName: string;
  paymentMethods: PaymentMethod[];
  usdtToNairaRate: number;
  geminiApiKey?: string;
}

export interface UserOrder {
  id: string;
  productId: string;
  productName: string;
  content: string;
  price: number;
  timestamp: number;
}

export interface User {
  id: string;
  email: string;
  password: string;
  balance: number;
  orders: UserOrder[];
}

export interface AdminUser {
  id: string;
  username: string;
  role: 'super' | 'editor';
}

export type ViewState = 'home' | 'category' | 'product' | 'cart' | 'profile' | 'admin_login' | 'admin_dashboard' | 'user_auth' | 'fund_wallet';

import React, { useState, useEffect } from 'react';
import { Product, CartItem, ViewState, Category, SiteSettings, AdminUser, User, UserOrder } from './types';
import { INITIAL_PRODUCTS, CATEGORIES } from './constants';
import Navbar from './components/Navbar';
import ProductCard from './components/ProductCard';
import GeminiAssistant from './components/GeminiAssistant';
import AdminLogin from './components/AdminLogin';
import AdminDashboard from './components/AdminDashboard';
import UserAuth from './components/UserAuth';
import UserProfile from './components/UserProfile';
import WalletFunding from './components/WalletFunding';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewState>('home');
  const [selectedCategory, setSelectedCategory] = useState<string | null>(null);
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [isProcessingCheckout, setIsProcessingCheckout] = useState(false);

  // Admin & Settings State
  const [products, setProducts] = useState<Product[]>(INITIAL_PRODUCTS);
  const [admins, setAdmins] = useState<AdminUser[]>([
    { id: '1', username: 'Admin', role: 'super' }
  ]);
  const [settings, setSettings] = useState<SiteSettings>({
    currency: 'NGN',
    currencySymbol: '₦',
    storeName: 'NETTOOLZ',
    usdtToNairaRate: 1650, 
    geminiApiKey: '',
    paymentMethods: [
      { 
        id: 'bank1', 
        type: 'bank', 
        name: 'KoralPay (Automated Bank)', 
        details: 'Transfer to the virtual account generated at checkout.', 
        isActive: true,
        isAutomated: true,
        apiPublicKey: 'pk_live_nettoolz_7721',
        merchantId: 'MER-88122'
      },
      { 
        id: 'crypto1', 
        type: 'crypto', 
        name: 'Crypto (Instant Credit)', 
        details: 'Payment credits after 1 network confirmation.', 
        walletAddress: 'TYxxxxxxxxxxxxxxxxxxxxxx',
        network: 'TRC20',
        isActive: true,
        isAutomated: true,
        apiPublicKey: 'pk_live_crypto_9921',
        merchantId: 'MER-99123'
      }
    ]
  });
  const [isAdminLoggedIn, setIsAdminLoggedIn] = useState(false);

  // User State
  const [users, setUsers] = useState<User[]>([]);
  const [currentUser, setCurrentUser] = useState<User | null>(null);

  // Persistence logic...
  useEffect(() => {
    const savedProducts = localStorage.getItem('nettoolz_products');
    if (savedProducts) setProducts(JSON.parse(savedProducts));
    const savedAdmin = localStorage.getItem('nettoolz_admin_logged');
    if (savedAdmin === 'true') setIsAdminLoggedIn(true);
    const savedUsers = localStorage.getItem('nettoolz_users');
    if (savedUsers) setUsers(JSON.parse(savedUsers));
    const savedSettings = localStorage.getItem('nettoolz_settings');
    if (savedSettings) setSettings(JSON.parse(savedSettings));
    const loggedUserEmail = localStorage.getItem('nettoolz_logged_user_email');
    if (loggedUserEmail && savedUsers) {
      const found = JSON.parse(savedUsers).find((u: User) => u.email === loggedUserEmail);
      if (found) setCurrentUser(found);
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('nettoolz_products', JSON.stringify(products));
    localStorage.setItem('nettoolz_users', JSON.stringify(users));
    localStorage.setItem('nettoolz_settings', JSON.stringify(settings));
    if (currentUser) localStorage.setItem('nettoolz_logged_user_email', currentUser.email);
    else localStorage.removeItem('nettoolz_logged_user_email');
  }, [products, users, currentUser, settings]);

  // Funding Logic
  const handleFundSuccess = (amount: number) => {
    if (!currentUser) return;
    const updatedUser = {
      ...currentUser,
      balance: currentUser.balance + amount
    };
    setUsers(prev => prev.map(u => u.email === updatedUser.email ? updatedUser : u));
    setCurrentUser(updatedUser);
  };

  const addToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      return [...prev, { ...product, quantity: 1 }];
    });
  };

  const handleCheckout = async () => {
    if (!currentUser) { setCurrentView('user_auth'); setIsCartOpen(false); return; }
    const total = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0);
    if (currentUser.balance < total) { alert('Insufficient balance.'); setCurrentView('fund_wallet'); setIsCartOpen(false); return; }

    setIsProcessingCheckout(true);
    await new Promise(resolve => setTimeout(resolve, 1500));
    const newOrders: UserOrder[] = cart.map(item => ({ id: Date.now().toString() + Math.random(), productId: item.id, productName: item.name, content: item.secretContent || 'Processing...', price: item.price, timestamp: Date.now() }));
    const updatedUser = { ...currentUser, balance: currentUser.balance - total, orders: [...currentUser.orders, ...newOrders] };
    setUsers(prev => prev.map(u => u.email === updatedUser.email ? updatedUser : u));
    setCurrentUser(updatedUser);
    setCart([]); setIsCartOpen(false); setIsProcessingCheckout(false); setCurrentView('profile');
    alert('Purchase confirmed!');
  };

  return (
    <div className="min-h-screen flex flex-col bg-sky-50 dark:bg-slate-950 transition-colors">
      <Navbar cartCount={cart.reduce((acc, item) => acc + item.quantity, 0)} isDarkMode={isDarkMode} onNavigate={setCurrentView} onOpenCart={() => setIsCartOpen(true)} onToggleTheme={() => { setIsDarkMode(!isDarkMode); document.documentElement.classList.toggle('dark'); }} />
      <main className="flex-1 max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 w-full">
        {currentView === 'home' && (
          <div className="space-y-16 py-12">
            <section className="relative px-6 py-20 bg-white dark:bg-slate-900 rounded-3xl border border-sky-100 dark:border-slate-800 overflow-hidden shadow-sm">
              <div className="relative z-10 text-center max-w-3xl mx-auto">
                <span className="inline-block px-4 py-2 bg-sky-100 dark:bg-sky-900/30 text-sky-600 dark:text-sky-400 rounded-full text-xs font-black uppercase mb-6 tracking-widest">Premium Digital Tools</span>
                <h1 className="text-5xl sm:text-6xl font-black text-slate-900 dark:text-white leading-tight mb-6">NET<span className="text-sky-500">TOOLZ</span> Enterprise</h1>
                <p className="text-lg text-slate-500 dark:text-slate-400 mb-10 leading-relaxed">Secure, automated access to high-performance proxies and VPNs.</p>
                <button onClick={() => setCurrentView('category')} className="bg-sky-500 hover:bg-sky-600 text-white font-bold px-10 py-4 rounded-2xl shadow-xl transition-all">Enter Catalog</button>
              </div>
            </section>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-8">
              {products.filter(p => p.isVisible).slice(0, 3).map(p => <ProductCard key={p.id} product={p} onAddToCart={addToCart} onViewDetails={(p) => { setSelectedProduct(p); setCurrentView('product'); }} />)}
            </div>
          </div>
        )}

        {currentView === 'category' && (
          <div className="py-12 flex flex-col md:flex-row gap-12">
            <div className="w-full md:w-64 space-y-4">
              <h3 className="text-lg font-black dark:text-white">Categories</h3>
              <div className="space-y-2">
                <button onClick={() => setSelectedCategory(null)} className={`w-full text-left px-4 py-2 rounded-xl ${!selectedCategory ? 'bg-sky-500 text-white font-bold' : 'bg-white dark:bg-slate-900 text-slate-400'}`}>All Assets</button>
                {CATEGORIES.map(cat => <button key={cat.id} onClick={() => setSelectedCategory(cat.id)} className={`w-full text-left px-4 py-2 rounded-xl ${selectedCategory === cat.id ? 'bg-sky-500 text-white font-bold' : 'bg-white dark:bg-slate-900 text-slate-400'}`}>{cat.name}</button>)}
              </div>
            </div>
            <div className="flex-1 grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
              {products.filter(p => p.isVisible && (!selectedCategory || p.category === selectedCategory)).map(p => <ProductCard key={p.id} product={p} onAddToCart={addToCart} onViewDetails={(p) => { setSelectedProduct(p); setCurrentView('product'); }} />)}
            </div>
          </div>
        )}

        {currentView === 'product' && selectedProduct && (
          <div className="py-12 max-w-5xl mx-auto">
            <div className="bg-white dark:bg-slate-900 rounded-3xl p-8 border border-sky-100 dark:border-slate-800 flex flex-col md:flex-row gap-12">
              <div className="flex-1 rounded-2xl overflow-hidden shadow-lg"><img src={selectedProduct.image} className="w-full h-full object-cover" /></div>
              <div className="flex-1 space-y-6">
                <h1 className="text-4xl font-black dark:text-white">{selectedProduct.name}</h1>
                <p className="text-3xl font-black text-sky-500">₦{selectedProduct.price.toLocaleString()}</p>
                <p className="text-slate-500 dark:text-slate-400">{selectedProduct.description}</p>
                <button onClick={() => addToCart(selectedProduct)} className="w-full bg-sky-500 text-white font-black py-4 rounded-xl shadow-lg">Add to Cart</button>
              </div>
            </div>
          </div>
        )}

        {currentView === 'user_auth' && <UserAuth users={users} onAuth={(u) => { setUsers([...users.filter(x => x.email !== u.email), u]); setCurrentUser(u); setCurrentView('profile'); }} onCancel={() => setCurrentView('home')} />}
        {currentView === 'profile' && currentUser && <UserProfile user={currentUser} settings={settings} onFundWallet={() => setCurrentView('fund_wallet')} onLogout={() => { setCurrentUser(null); setCurrentView('home'); }} />}
        {currentView === 'fund_wallet' && <WalletFunding settings={settings} onBack={() => setCurrentView('profile')} onFundSuccess={handleFundSuccess} />}
        {currentView === 'admin_dashboard' && isAdminLoggedIn && <AdminDashboard products={products} settings={settings} admins={admins} onUpdateProducts={setProducts} onUpdateSettings={setSettings} onUpdateAdmins={setAdmins} onLogout={() => { setIsAdminLoggedIn(false); setCurrentView('home'); }} />}
        {currentView === 'admin_login' && <AdminLogin onLogin={(s) => { if(s) { setIsAdminLoggedIn(true); setCurrentView('admin_dashboard'); } }} onCancel={() => setCurrentView('home')} />}
      </main>

      {/* Cart Drawer */}
      {isCartOpen && (
        <div className="fixed inset-0 z-[110] flex justify-end">
          <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={() => setIsCartOpen(false)}></div>
          <div className="relative w-full max-w-md bg-white dark:bg-slate-900 h-full p-8 flex flex-col">
            <h2 className="text-2xl font-black dark:text-white mb-8">Cart</h2>
            <div className="flex-1 overflow-y-auto space-y-4">
              {cart.map(item => (
                <div key={item.id} className="flex gap-4 p-4 bg-sky-50 dark:bg-slate-800 rounded-xl">
                  <div className="flex-1">
                    <p className="font-bold dark:text-white">{item.name}</p>
                    <p className="text-sky-500 font-bold">₦{item.price.toLocaleString()} x {item.quantity}</p>
                  </div>
                  <button onClick={() => setCart(cart.filter(i => i.id !== item.id))} className="text-red-400"><i className="fa-solid fa-trash"></i></button>
                </div>
              ))}
            </div>
            <div className="pt-8 border-t dark:border-slate-800 mt-6">
              <div className="flex justify-between text-2xl font-black mb-6 dark:text-white"><span>Total</span><span className="text-sky-500">₦{cart.reduce((a, i) => a + (i.price * i.quantity), 0).toLocaleString()}</span></div>
              <button onClick={handleCheckout} disabled={isProcessingCheckout || cart.length === 0} className="w-full bg-sky-500 text-white font-black py-4 rounded-xl">{isProcessingCheckout ? 'Processing...' : 'Complete Checkout'}</button>
            </div>
          </div>
        </div>
      )}

      <footer className="bg-white dark:bg-slate-900 border-t py-12 text-center">
        <p className="text-slate-400 text-xs font-black uppercase tracking-widest">© 2024 NETTOOLZ. Secure Digital Assets.</p>
        <button onClick={() => setCurrentView('admin_login')} className="mt-8 text-[10px] text-slate-300 hover:text-sky-500 font-black tracking-widest">ADMIN PORTAL</button>
      </footer>
      <GeminiAssistant />
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Product, Category, SiteSettings, AdminUser, PaymentMethod } from '../types';
import { CATEGORIES } from '../constants';
import { paymentService } from '../services/paymentService';

interface AdminDashboardProps {
  products: Product[];
  settings: SiteSettings;
  admins: AdminUser[];
  onUpdateProducts: (newProducts: Product[]) => void;
  onUpdateSettings: (newSettings: SiteSettings) => void;
  onUpdateAdmins: (newAdmins: AdminUser[]) => void;
  onLogout: () => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ 
  products, settings, admins, onUpdateProducts, onUpdateSettings, onUpdateAdmins, onLogout 
}) => {
  const [activeTab, setActiveTab] = useState<'products' | 'settings' | 'admins' | 'payments'>('products');
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [editingPayment, setEditingPayment] = useState<PaymentMethod | null>(null);
  const [productToDelete, setProductToDelete] = useState<Product | null>(null);
  const [isTestingApi, setIsTestingApi] = useState(false);
  const [apiTestResult, setApiTestResult] = useState<string | null>(null);
  const [showSecret, setShowSecret] = useState(false);

  const testApiConnection = async () => {
    if (!editingPayment) return;
    setIsTestingApi(true);
    setApiTestResult(null);

    // Simulate API handshake
    const res = await paymentService.initiateAutomatedPayment(
      'test', 
      1000, 
      { 
        publicKey: editingPayment.apiPublicKey, 
        merchantId: editingPayment.merchantId,
        type: editingPayment.type
      }
    );

    setApiTestResult(res.success ? "Connection Stable: API responded with 200 OK." : `Error: ${res.message}`);
    setIsTestingApi(false);
  };

  const handleSavePayment = (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingPayment) return;
    const existingIndex = settings.paymentMethods.findIndex(m => m.id === editingPayment.id);
    let newMethods;
    if (existingIndex > -1) {
      newMethods = settings.paymentMethods.map(m => m.id === editingPayment.id ? editingPayment : m);
    } else {
      newMethods = [...settings.paymentMethods, editingPayment];
    }
    onUpdateSettings({ ...settings, paymentMethods: newMethods });
    setEditingPayment(null);
    setApiTestResult(null);
  };

  return (
    <div className="flex flex-col md:flex-row min-h-[80vh] bg-white dark:bg-slate-900 rounded-3xl border border-sky-100 dark:border-slate-800 overflow-hidden shadow-xl mb-12">
      <div className="w-full md:w-64 bg-slate-900 text-white p-8">
        <h2 className="text-xl font-black mb-10 flex items-center space-x-2">
          <span className="bg-sky-500 p-1.5 rounded-lg"><i className="fa-solid fa-shield-halved"></i></span>
          <span>NETTOOLZ Admin</span>
        </h2>
        <nav className="space-y-2">
          <button onClick={() => setActiveTab('products')} className={`w-full text-left px-4 py-3 rounded-xl font-bold flex items-center space-x-3 ${activeTab === 'products' ? 'bg-sky-500' : 'text-slate-400 hover:bg-slate-800'}`}>
            <i className="fa-solid fa-box"></i><span>Inventory</span>
          </button>
          <button onClick={() => setActiveTab('payments')} className={`w-full text-left px-4 py-3 rounded-xl font-bold flex items-center space-x-3 ${activeTab === 'payments' ? 'bg-sky-500' : 'text-slate-400 hover:bg-slate-800'}`}>
            <i className="fa-solid fa-plug"></i><span>API Config</span>
          </button>
          <button onClick={() => setActiveTab('settings')} className={`w-full text-left px-4 py-3 rounded-xl font-bold flex items-center space-x-3 ${activeTab === 'settings' ? 'bg-sky-500' : 'text-slate-400 hover:bg-slate-800'}`}>
            <i className="fa-solid fa-gears"></i><span>General</span>
          </button>
        </nav>
        <button onClick={onLogout} className="mt-20 w-full text-left px-4 py-3 text-red-400 font-bold hover:bg-red-500/10 rounded-xl">
          <i className="fa-solid fa-power-off mr-2"></i>Logout
        </button>
      </div>

      <div className="flex-1 p-8 bg-sky-50/20 dark:bg-slate-900/40">
        <header className="flex justify-between items-center mb-10">
          <h3 className="text-3xl font-black dark:text-white capitalize">{activeTab}</h3>
          {activeTab === 'payments' && (
            <button 
              onClick={() => setEditingPayment({ id: Date.now().toString(), type: 'bank', name: 'New API Gateway', details: '', isActive: true, isAutomated: true })}
              className="bg-sky-500 text-white font-black px-6 py-2 rounded-xl shadow-lg"
            >
              Add New API
            </button>
          )}
        </header>

        {activeTab === 'settings' && (
          <div className="bg-white dark:bg-slate-800 p-8 rounded-2xl border border-sky-100 dark:border-slate-700 shadow-sm max-w-2xl">
            <h4 className="text-xl font-black mb-6 dark:text-white">Store Configuration</h4>
            <div className="space-y-6">
              <div>
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1 block">Store Name</label>
                <input 
                  type="text" 
                  value={settings.storeName} 
                  onChange={e => onUpdateSettings({...settings, storeName: e.target.value})}
                  className="w-full bg-sky-50 dark:bg-slate-900 p-3 rounded-xl border border-sky-100 dark:border-slate-700 dark:text-white focus:outline-none focus:ring-2 focus:ring-sky-500"
                />
              </div>
              <div>
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1 block">USDT to Naira Rate</label>
                <input 
                  type="number" 
                  value={settings.usdtToNairaRate} 
                  onChange={e => onUpdateSettings({...settings, usdtToNairaRate: Number(e.target.value)})}
                  className="w-full bg-sky-50 dark:bg-slate-900 p-3 rounded-xl border border-sky-100 dark:border-slate-700 dark:text-white focus:outline-none focus:ring-2 focus:ring-sky-500"
                />
              </div>
              <div className="pt-6 border-t border-sky-50 dark:border-slate-700">
                <h5 className="text-sm font-black text-sky-500 uppercase tracking-widest mb-4">AI Integration</h5>
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1 block">Gemini API Key</label>
                <div className="relative">
                  <input 
                    type={showSecret ? "text" : "password"} 
                    value={settings.geminiApiKey || ''} 
                    onChange={e => onUpdateSettings({...settings, geminiApiKey: e.target.value})}
                    className="w-full bg-sky-50 dark:bg-slate-900 p-3 rounded-xl border border-sky-100 dark:border-slate-700 dark:text-white font-mono text-sm focus:outline-none focus:ring-2 focus:ring-sky-500"
                    placeholder="Enter your Gemini API Key"
                  />
                  <button type="button" onClick={() => setShowSecret(!showSecret)} className="absolute right-3 top-3.5 text-slate-300 hover:text-sky-500 transition-colors">
                    <i className={`fa-solid ${showSecret ? 'fa-eye-slash' : 'fa-eye'}`}></i>
                  </button>
                </div>
                <p className="mt-2 text-[10px] text-slate-400 font-medium">This key is used by the Gemini Assistant for handling customer support queries.</p>
              </div>
            </div>
          </div>
        )}

        {activeTab === 'payments' && (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {settings.paymentMethods.map(method => (
              <div key={method.id} className="bg-white dark:bg-slate-800 p-6 rounded-2xl border border-sky-100 dark:border-slate-700 shadow-sm relative group">
                <div className="flex justify-between items-start mb-4">
                   <div className="bg-sky-50 dark:bg-slate-900 w-12 h-12 rounded-xl flex items-center justify-center text-sky-500 text-xl">
                      <i className={`fa-solid ${method.isAutomated ? 'fa-bolt' : 'fa-building-columns'}`}></i>
                   </div>
                   <div className="flex space-x-2">
                     <button onClick={() => setEditingPayment(method)} className="text-sky-500 hover:text-sky-600 transition-colors"><i className="fa-solid fa-pen-to-square"></i></button>
                   </div>
                </div>
                <h4 className="font-black text-lg dark:text-white">{method.name}</h4>
                <p className="text-xs text-slate-400 font-bold uppercase tracking-widest mt-1">
                  {method.isAutomated ? 'Automated Gateway' : 'Manual Transfer'}
                </p>
                <div className="mt-4 flex items-center justify-between">
                   <span className={`px-2 py-1 rounded text-[10px] font-black ${method.isActive ? 'bg-green-100 text-green-600' : 'bg-slate-100 text-slate-400'}`}>
                      {method.isActive ? 'ACTIVE' : 'DISABLED'}
                   </span>
                </div>
              </div>
            ))}
          </div>
        )}

        {activeTab === 'products' && (
          <div className="bg-white dark:bg-slate-800 rounded-2xl border border-sky-100 dark:border-slate-700 overflow-hidden shadow-sm">
            <table className="w-full text-left">
              <thead className="bg-sky-50 dark:bg-slate-900/50 text-slate-400 text-[10px] font-black uppercase tracking-widest">
                <tr><th className="px-6 py-4">Item</th><th className="px-6 py-4">Price</th><th className="px-6 py-4">Stock</th><th className="px-6 py-4 text-center">Action</th></tr>
              </thead>
              <tbody className="text-sm dark:text-slate-300">
                {products.map(p => (
                  <tr key={p.id} className="border-t border-sky-50 dark:border-slate-700 group hover:bg-sky-50/30 dark:hover:bg-slate-900/30 transition-colors">
                    <td className="px-6 py-4 font-bold">{p.name}</td>
                    <td className="px-6 py-4">₦{p.price.toLocaleString()}</td>
                    <td className="px-6 py-4">{p.stock}</td>
                    <td className="px-6 py-4">
                      <div className="flex justify-center space-x-4">
                        <button onClick={() => setEditingProduct(p)} className="text-sky-500 font-bold hover:underline">Edit</button>
                        <button onClick={() => setProductToDelete(p)} className="text-red-400 font-bold hover:underline">Delete</button>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>

      {/* Delete Confirmation Modal */}
      {productToDelete && (
        <div className="fixed inset-0 z-[300] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-900/90 backdrop-blur-sm" onClick={() => setProductToDelete(null)}></div>
          <div className="relative bg-white dark:bg-slate-900 w-full max-w-sm rounded-3xl shadow-2xl p-8 border border-red-100 dark:border-red-900/30 text-center animate-in zoom-in-95 duration-200">
            <div className="w-16 h-16 bg-red-50 dark:bg-red-900/20 text-red-500 rounded-full flex items-center justify-center text-2xl mx-auto mb-6">
              <i className="fa-solid fa-triangle-exclamation"></i>
            </div>
            <h3 className="text-xl font-black mb-2 dark:text-white">Delete Product?</h3>
            <p className="text-slate-500 dark:text-slate-400 text-sm mb-8 leading-relaxed">
              Are you sure you want to delete <span className="font-bold text-slate-800 dark:text-slate-200">"{productToDelete.name}"</span>? This action is permanent.
            </p>
            <div className="flex gap-3">
              <button 
                onClick={() => setProductToDelete(null)}
                className="flex-1 py-3 px-4 border-2 border-slate-100 text-sm font-bold rounded-xl text-slate-500 hover:bg-slate-50 dark:border-slate-800 dark:text-slate-400 dark:hover:bg-slate-800 transition-colors"
              >
                Keep it
              </button>
              <button 
                onClick={() => {
                  onUpdateProducts(products.filter(p => p.id !== productToDelete.id));
                  setProductToDelete(null);
                }}
                className="flex-1 py-3 px-4 bg-red-500 hover:bg-red-600 text-white text-sm font-bold rounded-xl shadow-lg shadow-red-100 dark:shadow-none transition-all active:scale-95"
              >
                Delete
              </button>
            </div>
          </div>
        </div>
      )}

      {/* API Config Modal */}
      {editingPayment && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-900/80 backdrop-blur-sm" onClick={() => setEditingPayment(null)}></div>
          <div className="relative bg-white dark:bg-slate-900 w-full max-w-xl rounded-3xl shadow-2xl p-8 border border-sky-200 dark:border-slate-700 animate-in zoom-in-95">
             <h3 className="text-2xl font-black mb-6 dark:text-white">API Configuration</h3>
             <form onSubmit={handleSavePayment} className="space-y-5">
                <div>
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1 block">Account Label</label>
                  <input type="text" value={editingPayment.name} onChange={e => setEditingPayment({...editingPayment, name: e.target.value})} className="w-full bg-sky-50 dark:bg-slate-800 p-3 rounded-xl border border-sky-100 dark:border-slate-700 dark:text-white focus:outline-none focus:ring-2 focus:ring-sky-500" required />
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <label className="flex items-center space-x-3 cursor-pointer p-3 rounded-xl border border-sky-100 dark:border-slate-700 bg-sky-50 dark:bg-slate-800">
                    <input type="checkbox" checked={editingPayment.isAutomated} onChange={e => setEditingPayment({...editingPayment, isAutomated: e.target.checked})} className="w-4 h-4 text-sky-500 rounded focus:ring-sky-500" />
                    <span className="text-sm font-black dark:text-white uppercase tracking-tighter">Enable API Integration</span>
                  </label>
                </div>

                {editingPayment.isAutomated && (
                  <div className="space-y-4 animate-in fade-in slide-in-from-top-2">
                     <div className="p-4 bg-sky-500/5 rounded-2xl border border-sky-500/20 space-y-4">
                        <div>
                          <label className="text-[10px] font-black text-sky-500 uppercase block mb-1">API Public Key</label>
                          <input type="text" value={editingPayment.apiPublicKey || ''} onChange={e => setEditingPayment({...editingPayment, apiPublicKey: e.target.value})} className="w-full bg-white dark:bg-slate-900 p-2 rounded-lg border border-sky-100 dark:border-slate-700 font-mono text-xs dark:text-white" placeholder="pk_live_..." />
                        </div>
                        <div>
                          <label className="text-[10px] font-black text-sky-500 uppercase block mb-1">API Secret Key</label>
                          <div className="relative">
                            <input type={showSecret ? "text" : "password"} value={editingPayment.apiSecretKey || ''} onChange={e => setEditingPayment({...editingPayment, apiSecretKey: e.target.value})} className="w-full bg-white dark:bg-slate-900 p-2 rounded-lg border border-sky-100 dark:border-slate-700 font-mono text-xs dark:text-white" placeholder="sk_live_..." />
                            <button type="button" onClick={() => setShowSecret(!showSecret)} className="absolute right-2 top-1.5 text-slate-300 hover:text-sky-500 transition-colors"><i className={`fa-solid ${showSecret ? 'fa-eye-slash' : 'fa-eye'}`}></i></button>
                          </div>
                        </div>
                        <div>
                          <label className="text-[10px] font-black text-sky-500 uppercase block mb-1">Merchant ID</label>
                          <input type="text" value={editingPayment.merchantId || ''} onChange={e => setEditingPayment({...editingPayment, merchantId: e.target.value})} className="w-full bg-white dark:bg-slate-900 p-2 rounded-lg border border-sky-100 dark:border-slate-700 font-mono text-xs dark:text-white" placeholder="MER-..." />
                        </div>

                        <div className="pt-2">
                           <button 
                            type="button" 
                            onClick={testApiConnection}
                            disabled={isTestingApi}
                            className="w-full py-2 bg-slate-900 dark:bg-slate-950 text-white text-[10px] font-black rounded-lg hover:bg-black transition-all flex items-center justify-center space-x-2 active:scale-95"
                           >
                             {isTestingApi ? <i className="fa-solid fa-spinner animate-spin"></i> : <i className="fa-solid fa-vial"></i>}
                             <span>{isTestingApi ? 'TESTING...' : 'RUN CONNECTIVITY TEST'}</span>
                           </button>
                           {apiTestResult && (
                             <p className={`mt-2 text-[10px] font-bold text-center ${apiTestResult.includes('Stable') ? 'text-green-500' : 'text-red-500'}`}>
                               {apiTestResult}
                             </p>
                           )}
                        </div>
                     </div>
                  </div>
                )}

                <div className="flex justify-end space-x-3 pt-6">
                  <button type="button" onClick={() => setEditingPayment(null)} className="px-6 py-2 text-slate-400 font-bold uppercase tracking-widest text-xs hover:text-slate-600 dark:hover:text-slate-300 transition-colors">Cancel</button>
                  <button type="submit" className="px-8 py-3 bg-sky-500 text-white font-black rounded-xl shadow-lg shadow-sky-100 dark:shadow-none active:scale-95 transition-all">Save Changes</button>
                </div>
             </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminDashboard;

import React, { useState } from 'react';
import { Product, Category, SiteSettings, AdminUser, PaymentMethod } from '../types';
import { CATEGORIES } from '../constants';
import { paymentService } from '../services/paymentService';

interface AdminDashboardProps {
  products: Product[];
  settings: SiteSettings;
  admins: AdminUser[];
  onUpdateProducts: (newProducts: Product[]) => void;
  onUpdateSettings: (newSettings: SiteSettings) => void;
  onUpdateAdmins: (newAdmins: AdminUser[]) => void;
  onLogout: () => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ 
  products, settings, admins, onUpdateProducts, onUpdateSettings, onUpdateAdmins, onLogout 
}) => {
  const [activeTab, setActiveTab] = useState<'products' | 'settings' | 'admins' | 'payments'>('products');
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [editingPayment, setEditingPayment] = useState<PaymentMethod | null>(null);
  const [productToDelete, setProductToDelete] = useState<Product | null>(null);
  const [showCreateForm, setShowCreateForm] = useState(false);
  const [isTestingApi, setIsTestingApi] = useState(false);
  const [apiTestResult, setApiTestResult] = useState<string | null>(null);
  const [showSecret, setShowSecret] = useState(false);

  // Form state for new product
  const [newProduct, setNewProduct] = useState({
    name: '',
    description: '',
    price: '',
    category: CATEGORIES[0].id,
    stock: '',
    image: '',
    features: '',
    secretContent: ''
  });

  const handleCreateProduct = (e: React.FormEvent) => {
    e.preventDefault();
    const product: Product = {
      id: Date.now().toString(),
      name: newProduct.name,
      description: newProduct.description,
      price: parseFloat(newProduct.price),
      category: newProduct.category,
      stock: parseInt(newProduct.stock),
      rating: 5.0,
      image: newProduct.image || 'https://picsum.photos/seed/tool/400/300',
      features: newProduct.features.split(',').map(f => f.trim()).filter(f => f !== ''),
      isVisible: true,
      secretContent: newProduct.secretContent
    };

    onUpdateProducts([product, ...products]);
    setShowCreateForm(false);
    setNewProduct({
      name: '',
      description: '',
      price: '',
      category: CATEGORIES[0].id,
      stock: '',
      image: '',
      features: '',
      secretContent: ''
    });
  };

  const testApiConnection = async () => {
    if (!editingPayment) return;
    setIsTestingApi(true);
    setApiTestResult(null);

    const res = await paymentService.initiateAutomatedPayment(
      'test', 
      1000, 
      { 
        publicKey: editingPayment.apiPublicKey, 
        merchantId: editingPayment.merchantId,
        type: editingPayment.type
      }
    );

    setApiTestResult(res.success ? "Connection Stable: API responded with 200 OK." : `Error: ${res.message}`);
    setIsTestingApi(false);
  };

  const handleSavePayment = (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingPayment) return;
    const existingIndex = settings.paymentMethods.findIndex(m => m.id === editingPayment.id);
    let newMethods;
    if (existingIndex > -1) {
      newMethods = settings.paymentMethods.map(m => m.id === editingPayment.id ? editingPayment : m);
    } else {
      newMethods = [...settings.paymentMethods, editingPayment];
    }
    onUpdateSettings({ ...settings, paymentMethods: newMethods });
    setEditingPayment(null);
    setApiTestResult(null);
  };

  return (
    <div className="flex flex-col md:flex-row min-h-[80vh] bg-white dark:bg-slate-900 rounded-3xl border border-sky-100 dark:border-slate-800 overflow-hidden shadow-xl mb-12">
      <div className="w-full md:w-64 bg-slate-900 text-white p-8 shrink-0">
        <h2 className="text-xl font-black mb-10 flex items-center space-x-2">
          <span className="bg-sky-500 p-1.5 rounded-lg"><i className="fa-solid fa-shield-halved"></i></span>
          <span>NETTOOLZ Admin</span>
        </h2>
        <nav className="space-y-2">
          <button onClick={() => setActiveTab('products')} className={`w-full text-left px-4 py-3 rounded-xl font-bold flex items-center space-x-3 transition-colors ${activeTab === 'products' ? 'bg-sky-500 text-white' : 'text-slate-400 hover:bg-slate-800'}`}>
            <i className="fa-solid fa-box"></i><span>Inventory</span>
          </button>
          <button onClick={() => setActiveTab('payments')} className={`w-full text-left px-4 py-3 rounded-xl font-bold flex items-center space-x-3 transition-colors ${activeTab === 'payments' ? 'bg-sky-500 text-white' : 'text-slate-400 hover:bg-slate-800'}`}>
            <i className="fa-solid fa-plug"></i><span>API Config</span>
          </button>
          <button onClick={() => setActiveTab('settings')} className={`w-full text-left px-4 py-3 rounded-xl font-bold flex items-center space-x-3 transition-colors ${activeTab === 'settings' ? 'bg-sky-500 text-white' : 'text-slate-400 hover:bg-slate-800'}`}>
            <i className="fa-solid fa-gears"></i><span>General</span>
          </button>
        </nav>
        <button onClick={onLogout} className="mt-20 w-full text-left px-4 py-3 text-red-400 font-bold hover:bg-red-500/10 rounded-xl transition-colors">
          <i className="fa-solid fa-power-off mr-2"></i>Logout
        </button>
      </div>

      <div className="flex-1 p-8 bg-sky-50/20 dark:bg-slate-900/40 overflow-y-auto">
        <header className="flex justify-between items-center mb-10">
          <h3 className="text-3xl font-black dark:text-white capitalize tracking-tight">{activeTab}</h3>
          <div className="flex items-center space-x-4">
            {activeTab === 'products' && (
              <button 
                onClick={() => setShowCreateForm(!showCreateForm)}
                className={`flex items-center space-x-2 font-black px-6 py-2.5 rounded-xl shadow-lg transition-all active:scale-95 ${showCreateForm ? 'bg-slate-800 text-white' : 'bg-sky-500 text-white'}`}
              >
                <i className={`fa-solid ${showCreateForm ? 'fa-xmark' : 'fa-plus'}`}></i>
                <span>{showCreateForm ? 'Cancel' : 'Add Product'}</span>
              </button>
            )}
            {activeTab === 'payments' && (
              <button 
                onClick={() => setEditingPayment({ id: Date.now().toString(), type: 'bank', name: 'New API Gateway', details: '', isActive: true, isAutomated: true })}
                className="bg-sky-500 text-white font-black px-6 py-2.5 rounded-xl shadow-lg"
              >
                Add New API
              </button>
            )}
          </div>
        </header>

        {activeTab === 'products' && showCreateForm && (
          <div className="mb-10 animate-in slide-in-from-top-4 duration-300">
            <form onSubmit={handleCreateProduct} className="bg-white dark:bg-slate-800 p-8 rounded-3xl border-2 border-sky-100 dark:border-slate-700 shadow-xl space-y-6">
              <div className="flex items-center space-x-3 mb-4">
                <div className="bg-sky-500 w-10 h-10 rounded-xl flex items-center justify-center text-white">
                  <i className="fa-solid fa-cart-plus"></i>
                </div>
                <h4 className="text-xl font-black dark:text-white">Create New Product</h4>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1 block">Product Name</label>
