          <div className="absolute inset-0 bg-slate-900/90 backdrop-blur-sm" onClick={() => setProductToDelete(null)}></div>
          <div className="relative bg-white dark:bg-slate-900 w-full max-w-sm rounded-3xl shadow-2xl p-8 border border-red-100 dark:border-red-900/30 text-center animate-in zoom-in-95 duration-200">
            <div className="w-16 h-16 bg-red-50 dark:bg-red-900/20 text-red-500 rounded-full flex items-center justify-center text-2xl mx-auto mb-6">
