      {/* API Config Modal */}
      {editingPayment && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-900/80 backdrop-blur-sm" onClick={() => setEditingPayment(null)}></div>
          <div className="relative bg-white dark:bg-slate-900 w-full max-w-xl rounded-3xl shadow-2xl p-8 border border-sky-200 dark:border-slate-700 animate-in zoom-in-95">
             <h3 className="text-2xl font-black mb-6 dark:text-white">API Configuration</h3>
             <form onSubmit={handleSavePayment} className="space-y-5">
                <div>
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1 block">Account Label</label>
                  <input type="text" value={editingPayment.name} onChange={e => setEditingPayment({...editingPayment, name: e.target.value})} className="w-full bg-sky-50 dark:bg-slate-800 p-3 rounded-xl border border-sky-100 dark:border-slate-700 dark:text-white focus:outline-none focus:ring-2 focus:ring-sky-500" required />
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <label className="flex items-center space-x-3 cursor-pointer p-3 rounded-xl border border-sky-100 dark:border-slate-700 bg-sky-50 dark:bg-slate-800">
                    <input type="checkbox" checked={editingPayment.isAutomated} onChange={e => setEditingPayment({...editingPayment, isAutomated: e.target.checked})} className="w-4 h-4 text-sky-500 rounded focus:ring-sky-500" />
                    <span className="text-sm font-black dark:text-white uppercase tracking-tighter">Enable API Integration</span>
                  </label>
                </div>

                {editingPayment.isAutomated && (
                  <div className="space-y-4 animate-in fade-in slide-in-from-top-2">
                     <div className="p-4 bg-sky-500/5 rounded-2xl border border-sky-500/20 space-y-4">
                        <div>
                          <label className="text-[10px] font-black text-sky-500 uppercase block mb-1">API Public Key</label>
                          <input type="text" value={editingPayment.apiPublicKey || ''} onChange={e => setEditingPayment({...editingPayment, apiPublicKey: e.target.value})} className="w-full bg-white dark:bg-slate-900 p-2 rounded-lg border border-sky-100 dark:border-slate-700 font-mono text-xs dark:text-white" placeholder="pk_live_..." />
                        </div>
                        <div>
                          <label className="text-[10px] font-black text-sky-500 uppercase block mb-1">API Secret Key</label>
                          <div className="relative">
                            <input type={showSecret ? "text" : "password"} value={editingPayment.apiSecretKey || ''} onChange={e => setEditingPayment({...editingPayment, apiSecretKey: e.target.value})} className="w-full bg-white dark:bg-slate-900 p-2 rounded-lg border border-sky-100 dark:border-slate-700 font-mono text-xs dark:text-white" placeholder="sk_live_..." />
                            <button type="button" onClick={() => setShowSecret(!showSecret)} className="absolute right-2 top-1.5 text-slate-300 hover:text-sky-500 transition-colors"><i className={`fa-solid ${showSecret ? 'fa-eye-slash' : 'fa-eye'}`}></i></button>
                          </div>
                        </div>
                        <div>
                          <label className="text-[10px] font-black text-sky-500 uppercase block mb-1">Merchant ID</label>
                          <input type="text" value={editingPayment.merchantId || ''} onChange={e => setEditingPayment({...editingPayment, merchantId: e.target.value})} className="w-full bg-white dark:bg-slate-900 p-2 rounded-lg border border-sky-100 dark:border-slate-700 font-mono text-xs dark:text-white" placeholder="MER-..." />
                        </div>

                        <div className="pt-2">
                           <button 
                            type="button" 
                            onClick={testApiConnection}
                            disabled={isTestingApi}
                            className="w-full py-2 bg-slate-900 dark:bg-slate-950 text-white text-[10px] font-black rounded-lg hover:bg-black transition-all flex items-center justify-center space-x-2 active:scale-95"
                           >
                             {isTestingApi ? <i className="fa-solid fa-spinner animate-spin"></i> : <i className="fa-solid fa-vial"></i>}
                             <span>{isTestingApi ? 'TESTING...' : 'RUN CONNECTIVITY TEST'}</span>
                           </button>
                           {apiTestResult && (
                             <p className={`mt-2 text-[10px] font-bold text-center ${apiTestResult.includes('Stable') ? 'text-green-500' : 'text-red-500'}`}>
                               {apiTestResult}
