}

export interface PaymentMethod {
  id: string;
  type: 'bank' | 'crypto';
  name: string;
  details: string;
  isActive: boolean;
  bankName?: string;
  accountNumber?: string;
  accountName?: string;
  walletAddress?: string;
  network?: string;
