            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-8">
              {products.filter(p => p.isVisible).slice(0, 3).map(p => <ProductCard key={p.id} product={p} onAddToCart={addToCart} onViewDetails={(p) => { setSelectedProduct(p); setCurrentView('product'); }} />)}
            </div>
          </div>
        )}

        {currentView === 'category' && (
          <div className="py-12 flex flex-col md:flex-row gap-12">
            <div className="w-full md:w-64 space-y-4">
              <h3 className="text-lg font-black dark:text-white">Categories</h3>
              <div className="space-y-2">
                <button onClick={() => setSelectedCategory(null)} className={`w-full text-left px-4 py-2 rounded-xl transition-all ${!selectedCategory ? 'bg-sky-500 text-white font-bold' : 'bg-white dark:bg-slate-900 text-slate-400 hover:bg-sky-50 dark:hover:bg-slate-800'}`}>All Assets</button>
                {settings.categories.map(cat => <button key={cat.id} onClick={() => setSelectedCategory(cat.id)} className={`w-full text-left px-4 py-2 rounded-xl transition-all ${selectedCategory === cat.id ? 'bg-sky-500 text-white font-bold' : 'bg-white dark:bg-slate-900 text-slate-400 hover:bg-sky-50 dark:hover:bg-slate-800'}`}>{cat.name}</button>)}
              </div>
            </div>
            <div className="flex-1 grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
              {products.filter(p => p.isVisible && (!selectedCategory || p.category === selectedCategory)).map(p => <ProductCard key={p.id} product={p} onAddToCart={addToCart} onViewDetails={(p) => { setSelectedProduct(p); setCurrentView('product'); }} />)}
            </div>
          </div>
        )}

        {currentView === 'product' && selectedProduct && (
          <div className="py-12 max-w-5xl mx-auto">
            <div className="bg-white dark:bg-slate-900 rounded-3xl p-8 border border-sky-100 dark:border-slate-800 flex flex-col md:flex-row gap-12">
              <div className="flex-1 rounded-2xl overflow-hidden shadow-lg bg-sky-50 dark:bg-slate-800"><img src={selectedProduct.image} className="w-full h-full object-cover" /></div>
              <div className="flex-1 space-y-6">
                <h1 className="text-4xl font-black dark:text-white">{selectedProduct.name}</h1>
                <p className="text-3xl font-black text-sky-500">₦{selectedProduct.price.toLocaleString()}</p>
                <p className="text-slate-500 dark:text-slate-400">{selectedProduct.description}</p>
                <button onClick={() => addToCart(selectedProduct)} className="w-full bg-sky-500 text-white font-black py-4 rounded-xl shadow-lg transition-all active:scale-95">Add to Cart</button>
              </div>
            </div>
          </div>
        )}

        {currentView === 'user_auth' && <UserAuth users={users} onAuth={(u) => { setUsers([...users.filter(x => x.email !== u.email), u]); setCurrentUser(u); setCurrentView('profile'); }} onCancel={() => setCurrentView('home')} />}
        {currentView === 'profile' && currentUser && <UserProfile user={currentUser} settings={settings} onFundWallet={() => setCurrentView('fund_wallet')} onLogout={() => { setCurrentUser(null); setCurrentView('home'); }} />}
        {currentView === 'fund_wallet' && <WalletFunding settings={settings} onBack={() => setCurrentView('profile')} onFundSuccess={handleFundSuccess} />}
        {currentView === 'admin_dashboard' && isAdminLoggedIn && <AdminDashboard products={products} settings={settings} admins={admins} onUpdateProducts={setProducts} onUpdateSettings={setSettings} onUpdateAdmins={setAdmins} onLogout={() => { setIsAdminLoggedIn(false); setCurrentView('home'); }} />}
        {currentView === 'admin_login' && <AdminLogin onLogin={(s) => { if(s) { setIsAdminLoggedIn(true); setCurrentView('admin_dashboard'); } }} onCancel={() => setCurrentView('home')} />}
      </main>

      {/* Cart Drawer */}
      {isCartOpen && (
        <div className="fixed inset-0 z-[110] flex justify-end">
          <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={() => setIsCartOpen(false)}></div>
          <div className="relative w-full max-w-md bg-white dark:bg-slate-900 h-full p-8 flex flex-col shadow-2xl">
            <h2 className="text-2xl font-black dark:text-white mb-8">Cart</h2>
            <div className="flex-1 overflow-y-auto space-y-4">
              {cart.map(item => (
                <div key={item.id} className="flex gap-4 p-4 bg-sky-50 dark:bg-slate-800 rounded-xl">
                  <div className="flex-1">
                    <p className="font-bold dark:text-white">{item.name}</p>
                    <p className="text-sky-500 font-bold">₦{item.price.toLocaleString()} x {item.quantity}</p>
                  </div>
                  <button onClick={() => setCart(cart.filter(i => i.id !== item.id))} className="text-red-400 hover:text-red-600 transition-colors"><i className="fa-solid fa-trash"></i></button>
                </div>
              ))}
              {cart.length === 0 && (
                <div className="text-center py-20 text-slate-400">
                  <i className="fa-solid fa-cart-arrow-down text-4xl mb-4"></i>
                  <p>Your cart is empty.</p>
                </div>
              )}
            </div>
            <div className="pt-8 border-t dark:border-slate-800 mt-6">
              <div className="flex justify-between text-2xl font-black mb-6 dark:text-white"><span>Total</span><span className="text-sky-500">₦{cart.reduce((a, i) => a + (i.price * i.quantity), 0).toLocaleString()}</span></div>
              <button onClick={handleCheckout} disabled={isProcessingCheckout || cart.length === 0} className="w-full bg-sky-500 text-white font-black py-4 rounded-xl hover:bg-sky-600 transition-all active:scale-95 disabled:bg-slate-300">{isProcessingCheckout ? 'Processing...' : 'Complete Checkout'}</button>
            </div>
          </div>
        </div>
      )}

      <footer className="bg-white dark:bg-slate-900 border-t py-12 text-center transition-colors">
        <p className="text-slate-400 text-xs font-black uppercase tracking-widest">© 2024 NETTOOLZ. Secure Digital Assets.</p>
        <button onClick={() => setCurrentView('admin_login')} className="mt-8 text-[10px] text-slate-300 hover:text-sky-500 font-black tracking-widest">ADMIN PORTAL</button>
      </footer>
      <GeminiAssistant />
    </div>
  );
};

export default App;

import React, { useState, useRef } from 'react';
import { Product, Category, SiteSettings, AdminUser, PaymentMethod } from '../types';
import { paymentService } from '../services/paymentService';

interface AdminDashboardProps {
  products: Product[];
  settings: SiteSettings;
  admins: AdminUser[];
  onUpdateProducts: (newProducts: Product[]) => void;
  onUpdateSettings: (newSettings: SiteSettings) => void;
  onUpdateAdmins: (newAdmins: AdminUser[]) => void;
  onLogout: () => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ 
  products, settings, admins, onUpdateProducts, onUpdateSettings, onUpdateAdmins, onLogout 
}) => {
  const [activeTab, setActiveTab] = useState<'products' | 'categories' | 'settings' | 'admins' | 'payments'>('products');
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [editingCategory, setEditingCategory] = useState<Category | null>(null);
  const [editingPayment, setEditingPayment] = useState<PaymentMethod | null>(null);
  const [productToDelete, setProductToDelete] = useState<Product | null>(null);
  const [categoryToDelete, setCategoryToDelete] = useState<Category | null>(null);
  const [showCreateForm, setShowCreateForm] = useState(false);
  const [showCategoryForm, setShowCategoryForm] = useState(false);
  const [isTestingApi, setIsTestingApi] = useState(false);
  const [apiTestResult, setApiTestResult] = useState<string | null>(null);
  const [showSecret, setShowSecret] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const editFileInputRef = useRef<HTMLInputElement>(null);

  // Form state for new product
  const [newProduct, setNewProduct] = useState({
    name: '',
    description: '',
    price: '',
    category: settings.categories[0]?.id || '',
    stock: '',
    image: '',
    features: '',
    secretContent: ''
  });

  // Form state for new category
  const [newCategory, setNewCategory] = useState({
    name: '',
    icon: 'fa-box'
  });

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>, isEdit = false) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64 = reader.result as string;
        if (isEdit && editingProduct) {
          setEditingProduct({ ...editingProduct, image: base64 });
        } else {
          setNewProduct({ ...newProduct, image: base64 });
        }
      };
      reader.readAsDataURL(file);
    }
  };

  const handleCreateProduct = (e: React.FormEvent) => {
    e.preventDefault();
    const product: Product = {
      id: Date.now().toString(),
      name: newProduct.name,
      description: newProduct.description,
      price: parseFloat(newProduct.price),
      category: newProduct.category,
      stock: parseInt(newProduct.stock),
      rating: 5.0,
      image: newProduct.image || 'https://picsum.photos/seed/tool/400/300',
      features: newProduct.features.split(',').map(f => f.trim()).filter(f => f !== ''),
      isVisible: true,
      secretContent: newProduct.secretContent
    };

    onUpdateProducts([product, ...products]);
    setShowCreateForm(false);
    setNewProduct({
      name: '',
      description: '',
      price: '',
      category: settings.categories[0]?.id || '',
      stock: '',
      image: '',
      features: '',
      secretContent: ''
    });
  };

  const handleSaveProductEdit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingProduct) return;
    onUpdateProducts(products.map(p => p.id === editingProduct.id ? editingProduct : p));
    setEditingProduct(null);
  };

  const handleCreateCategory = (e: React.FormEvent) => {
    e.preventDefault();
    const cat: Category = {
      id: newCategory.name.toLowerCase().replace(/\s+/g, '-'),
      name: newCategory.name,
      icon: newCategory.icon
    };
    onUpdateSettings({ ...settings, categories: [...settings.categories, cat] });
    setShowCategoryForm(false);
    setNewCategory({ name: '', icon: 'fa-box' });
  };

  const handleSaveCategoryEdit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingCategory) return;
    onUpdateSettings({
      ...settings,
      categories: settings.categories.map(c => c.id === editingCategory.id ? editingCategory : c)
    });
    setEditingCategory(null);
  };

  const testApiConnection = async () => {
    if (!editingPayment) return;
    setIsTestingApi(true);
    setApiTestResult(null);

    const res = await paymentService.initiateAutomatedPayment(
      'test', 
      1000, 
      { 
        publicKey: editingPayment.apiPublicKey, 
        merchantId: editingPayment.merchantId,
        type: editingPayment.type
      }
    );

    setApiTestResult(res.success ? "Connection Stable: API responded with 200 OK." : `Error: ${res.message}`);
    setIsTestingApi(false);
  };

  const handleSavePayment = (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingPayment) return;
    const existingIndex = settings.paymentMethods.findIndex(m => m.id === editingPayment.id);
    let newMethods;
    if (existingIndex > -1) {
      newMethods = settings.paymentMethods.map(m => m.id === editingPayment.id ? editingPayment : m);
    } else {
      newMethods = [...settings.paymentMethods, editingPayment];
    }
    onUpdateSettings({ ...settings, paymentMethods: newMethods });
    setEditingPayment(null);
    setApiTestResult(null);
  };

  return (
    <div className="flex flex-col md:flex-row min-h-[80vh] bg-white dark:bg-slate-900 rounded-3xl border border-sky-100 dark:border-slate-800 overflow-hidden shadow-xl mb-12">
      <div className="w-full md:w-64 bg-slate-900 text-white p-8 shrink-0">
        <h2 className="text-xl font-black mb-10 flex items-center space-x-2">
          <span className="bg-sky-500 p-1.5 rounded-lg"><i className="fa-solid fa-shield-halved"></i></span>
          <span>NETTOOLZ Admin</span>
        </h2>
        <nav className="space-y-2">
          <button onClick={() => setActiveTab('products')} className={`w-full text-left px-4 py-3 rounded-xl font-bold flex items-center space-x-3 transition-colors ${activeTab === 'products' ? 'bg-sky-500 text-white' : 'text-slate-400 hover:bg-slate-800'}`}>
            <i className="fa-solid fa-box"></i><span>Inventory</span>
          </button>
          <button onClick={() => setActiveTab('categories')} className={`w-full text-left px-4 py-3 rounded-xl font-bold flex items-center space-x-3 transition-colors ${activeTab === 'categories' ? 'bg-sky-500 text-white' : 'text-slate-400 hover:bg-slate-800'}`}>
            <i className="fa-solid fa-tags"></i><span>Categories</span>
          </button>
          <button onClick={() => setActiveTab('payments')} className={`w-full text-left px-4 py-3 rounded-xl font-bold flex items-center space-x-3 transition-colors ${activeTab === 'payments' ? 'bg-sky-500 text-white' : 'text-slate-400 hover:bg-slate-800'}`}>
            <i className="fa-solid fa-plug"></i><span>API Config</span>
          </button>
          <button onClick={() => setActiveTab('settings')} className={`w-full text-left px-4 py-3 rounded-xl font-bold flex items-center space-x-3 transition-colors ${activeTab === 'settings' ? 'bg-sky-500 text-white' : 'text-slate-400 hover:bg-slate-800'}`}>
            <i className="fa-solid fa-gears"></i><span>General</span>
          </button>
        </nav>
        <button onClick={onLogout} className="mt-20 w-full text-left px-4 py-3 text-red-400 font-bold hover:bg-red-500/10 rounded-xl transition-colors">
          <i className="fa-solid fa-power-off mr-2"></i>Logout
        </button>
      </div>

      <div className="flex-1 p-8 bg-sky-50/20 dark:bg-slate-900/40 overflow-y-auto">
        <header className="flex justify-between items-center mb-10">
          <h3 className="text-3xl font-black dark:text-white capitalize tracking-tight">{activeTab}</h3>
          <div className="flex items-center space-x-4">
            {activeTab === 'products' && (
              <button 
                onClick={() => setShowCreateForm(!showCreateForm)}
                className={`flex items-center space-x-2 font-black px-6 py-2.5 rounded-xl shadow-lg transition-all active:scale-95 ${showCreateForm ? 'bg-slate-800 text-white' : 'bg-sky-500 text-white'}`}
              >
                <i className={`fa-solid ${showCreateForm ? 'fa-xmark' : 'fa-plus'}`}></i>
                <span>{showCreateForm ? 'Cancel' : 'Add Product'}</span>
              </button>
            )}
            {activeTab === 'categories' && (
              <button 
                onClick={() => setShowCategoryForm(!showCategoryForm)}
                className="bg-sky-500 text-white font-black px-6 py-2.5 rounded-xl shadow-lg transition-all active:scale-95"
              >
                <i className="fa-solid fa-plus mr-2"></i>New Category
              </button>
            )}
            {activeTab === 'payments' && (
              <button 
                onClick={() => setEditingPayment({ id: Date.now().toString(), type: 'bank', name: 'New API Gateway', details: '', isActive: true, isAutomated: true })}
                className="bg-sky-500 text-white font-black px-6 py-2.5 rounded-xl shadow-lg"
              >
                Add New API
              </button>
            )}
          </div>
        </header>

        {/* Categories Tab Content */}
        {activeTab === 'categories' && (
          <div className="space-y-6">
            {showCategoryForm && (
              <form onSubmit={handleCreateCategory} className="bg-white dark:bg-slate-800 p-8 rounded-3xl border-2 border-sky-100 dark:border-slate-700 shadow-xl space-y-4 animate-in slide-in-from-top-4">
                <h4 className="text-xl font-black dark:text-white mb-4">Create New Category</h4>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div>
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1 block">Category Name</label>
                    <input required type="text" value={newCategory.name} onChange={e => setNewCategory({...newCategory, name: e.target.value})} className="w-full bg-sky-50 dark:bg-slate-900 p-3 rounded-xl border border-sky-100 dark:border-slate-700 dark:text-white outline-none" placeholder="e.g. Dedicated Proxies" />
                  </div>
                  <div>
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1 block">FontAwesome Icon</label>
                    <input required type="text" value={newCategory.icon} onChange={e => setNewCategory({...newCategory, icon: e.target.value})} className="w-full bg-sky-50 dark:bg-slate-900 p-3 rounded-xl border border-sky-100 dark:border-slate-700 dark:text-white outline-none" placeholder="fa-server" />
                  </div>
                </div>
                <div className="flex justify-end space-x-3 pt-4">
                  <button type="button" onClick={() => setShowCategoryForm(false)} className="text-slate-400 font-bold uppercase text-xs tracking-widest">Discard</button>
                  <button type="submit" className="bg-sky-500 text-white font-black px-8 py-3 rounded-xl shadow-lg">Create Category</button>
                </div>
              </form>
            )}

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {settings.categories.map(cat => (
                <div key={cat.id} className="bg-white dark:bg-slate-800 p-6 rounded-2xl border border-sky-100 dark:border-slate-700 shadow-sm flex items-center justify-between group transition-all hover:border-sky-300">
                  <div className="flex items-center space-x-4">
                    <div className="w-12 h-12 bg-sky-50 dark:bg-slate-900 text-sky-500 rounded-xl flex items-center justify-center text-xl">
                      <i className={`fa-solid ${cat.icon}`}></i>
                    </div>
                    <div>
                      <h4 className="font-black dark:text-white">{cat.name}</h4>
                      <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">ID: {cat.id}</p>
                    </div>
                  </div>
                  <div className="flex space-x-2">
                    <button onClick={() => setEditingCategory(cat)} className="text-sky-500 hover:text-sky-600 p-2"><i className="fa-solid fa-pen"></i></button>
                    <button onClick={() => setCategoryToDelete(cat)} className="text-red-400 hover:text-red-500 p-2"><i className="fa-solid fa-trash"></i></button>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {activeTab === 'products' && showCreateForm && (
          <div className="mb-10 animate-in slide-in-from-top-4 duration-300">
            <form onSubmit={handleCreateProduct} className="bg-white dark:bg-slate-800 p-8 rounded-3xl border-2 border-sky-100 dark:border-slate-700 shadow-xl space-y-6">
              <div className="flex items-center space-x-3 mb-4">
                <div className="bg-sky-500 w-10 h-10 rounded-xl flex items-center justify-center text-white">
                  <i className="fa-solid fa-cart-plus"></i>
                </div>
                <h4 className="text-xl font-black dark:text-white">Create New Product</h4>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1 block">Product Name</label>
                  <input required type="text" value={newProduct.name} onChange={e => setNewProduct({...newProduct, name: e.target.value})} className="w-full bg-sky-50 dark:bg-slate-900 p-3 rounded-xl border border-sky-100 dark:border-slate-700 dark:text-white focus:ring-2 focus:ring-sky-500 outline-none" placeholder="e.g. Premium Residential Proxies" />
                </div>
                <div>
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1 block">Category</label>
                  <select value={newProduct.category} onChange={e => setNewProduct({...newProduct, category: e.target.value})} className="w-full bg-sky-50 dark:bg-slate-900 p-3 rounded-xl border border-sky-100 dark:border-slate-700 dark:text-white focus:ring-2 focus:ring-sky-500 outline-none">
                    {settings.categories.map(cat => <option key={cat.id} value={cat.id}>{cat.name}</option>)}
                  </select>
                </div>
                <div>
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1 block">Price (NGN)</label>
                  <input required type="number" step="0.01" value={newProduct.price} onChange={e => setNewProduct({...newProduct, price: e.target.value})} className="w-full bg-sky-50 dark:bg-slate-900 p-3 rounded-xl border border-sky-100 dark:border-slate-700 dark:text-white focus:ring-2 focus:ring-sky-500 outline-none" placeholder="0.00" />
                </div>
                <div>
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1 block">Initial Stock</label>
                  <input required type="number" value={newProduct.stock} onChange={e => setNewProduct({...newProduct, stock: e.target.value})} className="w-full bg-sky-50 dark:bg-slate-900 p-3 rounded-xl border border-sky-100 dark:border-slate-700 dark:text-white focus:ring-2 focus:ring-sky-500 outline-none" placeholder="0" />
                </div>
                <div className="md:col-span-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 block">Product Photo</label>
                  <div className="flex items-center space-x-6">
                    <div className="w-32 h-32 rounded-2xl bg-sky-50 dark:bg-slate-900 border-2 border-dashed border-sky-200 dark:border-slate-700 flex items-center justify-center overflow-hidden shrink-0">
                      {newProduct.image ? (
                        <img src={newProduct.image} className="w-full h-full object-cover" />
                      ) : (
                        <i className="fa-solid fa-image text-slate-300 text-3xl"></i>
                      )}
                    </div>
                    <div className="space-y-2">
                      <input 
                        type="file" 
                        ref={fileInputRef} 
                        onChange={(e) => handleImageUpload(e)} 
                        className="hidden" 
                        accept="image/*" 
                      />
                      <button 
                        type="button" 
                        onClick={() => fileInputRef.current?.click()}
                        className="bg-white dark:bg-slate-800 border border-sky-200 dark:border-slate-700 px-4 py-2 rounded-xl text-sm font-black text-sky-600 dark:text-sky-400 shadow-sm transition-all active:scale-95"
                      >
                        <i className="fa-solid fa-upload mr-2"></i>Choose Photo
                      </button>
                      <p className="text-[10px] text-slate-400 font-medium">Recommended: 800x600px PNG or JPG</p>
                    </div>
                  </div>
                </div>
                <div className="md:col-span-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1 block">Description</label>
                  <textarea required value={newProduct.description} onChange={e => setNewProduct({...newProduct, description: e.target.value})} className="w-full bg-sky-50 dark:bg-slate-900 p-3 rounded-xl border border-sky-100 dark:border-slate-700 dark:text-white focus:ring-2 focus:ring-sky-500 outline-none h-24" placeholder="Brief details about the product..." />
                </div>
