/**
 * Creates a new chat session using the Gemini 3 Pro model.
 * This model is optimized for the complex technical queries common in the NETTOOLZ catalog.
 */
export const startNETTOOLZChat = (): Chat => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  return ai.chats.create({
    model: 'gemini-3-pro-preview',
    config: {
      systemInstruction: `You are the NETTOOLZ Pro Assistant, a world-class expert in digital networking tools, security software, and digital assets.

      Your core knowledge base includes:
      - Private & Residential Proxies (SOCKS5, HTTP/S, IP rotation, mobile vs. residential).
      - Premium VPNs (Encryption protocols, Kill Switches, geo-unblocking).
      - RDP & VPS (Windows Server administration, remote access, latency optimization).
      - Traffic Logs & SEO Tools.

      Guidelines:
      1. Professional & Precise: Use technical terminology correctly but explain it simply if the user seems like a beginner.
      2. Promotional: Highlight that NETTOOLZ is the premier source for these high-performance assets.
      3. Safety First: If users ask about illegal hacking or abusive activities, strictly decline and redirect them to ethical professional use cases like penetration testing, privacy protection, or market research.
      4. Concise: Provide actionable steps. Don't write long essays unless the user asks for a deep dive.`,
      temperature: 0.8,
      thinkingConfig: { thinkingBudget: 16384 },
    },
  });
};

import React, { useState, useRef, useEffect } from 'react';
import { startNETTOOLZChat } from '../services/geminiService';
import { Chat, GenerateContentResponse } from '@google/genai';

const SUGGESTIONS = [
  "How to setup Proxies?",
  "Best VPN for privacy?",
  "RDP vs VPS?",
  "Wallet funding help"
];

const GeminiAssistant: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<{ role: 'user' | 'ai'; text: string }[]>([
    { role: 'ai', text: 'Welcome to the NETTOOLZ Pro Portal. I am your specialized AI assistant. How can I help you optimize your digital stack today?' }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [chatSession, setChatSession] = useState<Chat | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    if (isOpen) scrollToBottom();
  }, [messages, isOpen]);

  // Initialize chat session when chat is opened
  useEffect(() => {
    if (isOpen && !chatSession) {
      try {
        const session = startNETTOOLZChat();
        setChatSession(session);
      } catch (err) {
        console.error("Failed to init chat:", err);
      }
    }
  }, [isOpen, chatSession]);

  const handleSend = async (customMsg?: string) => {
    const textToSend = (customMsg || input).trim();
    if (!textToSend || isTyping) return;

    setMessages(prev => [...prev, { role: 'user', text: textToSend }]);
    if (!customMsg) setInput('');
    setIsTyping(true);

    try {
      if (!chatSession) throw new Error("Chat session not initialized");

      const response: GenerateContentResponse = await chatSession.sendMessage({ message: textToSend });
