const DB_NAME = 'NetToolzDB';
const DB_VERSION = 1;

export class DatabaseService {
  private db: IDBDatabase | null = null;

  async init(): Promise<void> {
    return new Promise((resolve, reject) => {
      const request = indexedDB.open(DB_NAME, DB_VERSION);

      request.onupgradeneeded = (event: any) => {
        const db = event.target.result;
        if (!db.objectStoreNames.contains('products')) {
          db.createObjectStore('products', { keyPath: 'id' });
        }
        if (!db.objectStoreNames.contains('users')) {
          db.createObjectStore('users', { keyPath: 'email' });
        }
        if (!db.objectStoreNames.contains('settings')) {
          db.createObjectStore('settings', { keyPath: 'id' });
        }
      };

      request.onsuccess = (event: any) => {
        this.db = event.target.result;
        resolve();
      };

      request.onerror = (event: any) => {
        reject('IndexedDB error: ' + event.target.errorCode);
      };
    });
  }

  private async getStore(storeName: string, mode: IDBTransactionMode = 'readonly'): Promise<IDBObjectStore> {
    if (!this.db) await this.init();
    const transaction = this.db!.transaction(storeName, mode);
    return transaction.objectStore(storeName);
  }

  // Products
  async getAllProducts(): Promise<Product[]> {
    const store = await this.getStore('products');
    return new Promise((resolve) => {
      const request = store.getAll();
      request.onsuccess = () => resolve(request.result);
    });
  }

  async saveProducts(products: Product[]): Promise<void> {
    const store = await this.getStore('products', 'readwrite');
    store.clear();
    products.forEach(p => store.put(p));
  }

  // Users
  async getAllUsers(): Promise<User[]> {
    const store = await this.getStore('users');
    return new Promise((resolve) => {
      const request = store.getAll();
      request.onsuccess = () => resolve(request.result);
    });
  }

  async saveUser(user: User): Promise<void> {
    const store = await this.getStore('users', 'readwrite');
    return new Promise((resolve) => {
      const request = store.put(user);
      request.onsuccess = () => resolve();
    });
  }

  // Settings
  async getSettings(): Promise<SiteSettings | null> {
    const store = await this.getStore('settings');
    return new Promise((resolve) => {
      const request = store.get('main_config');
      request.onsuccess = () => resolve(request.result || null);
    });
  }

  async saveSettings(settings: SiteSettings): Promise<void> {
    const store = await this.getStore('settings', 'readwrite');
    return new Promise((resolve) => {
      const request = store.put({ ...settings, id: 'main_config' });
      request.onsuccess = () => resolve();
    });
  }
}

export const dbService = new DatabaseService();

import React, { useState, useEffect } from 'react';
import { Product, CartItem, ViewState, SiteSettings, AdminUser, User, UserOrder } from './types';
import { INITIAL_PRODUCTS, CATEGORIES } from './constants';
