                  <input 
                    type={showSecret ? "text" : "password"} 
                    value={settings.geminiApiKey || ''} 
                    onChange={e => onUpdateSettings({...settings, geminiApiKey: e.target.value})}
                    className="w-full bg-sky-50 dark:bg-slate-900 p-3 rounded-xl border border-sky-100 dark:border-slate-700 dark:text-white font-mono text-sm focus:outline-none focus:ring-2 focus:ring-sky-500 transition-colors"
