              <button onClick={() => { onUpdateProducts(products.filter(p => p.id !== productToDelete.id)); setProductToDelete(null); }} className="flex-1 py-3 px-4 bg-red-500 hover:bg-red-600 text-white text-sm font-bold rounded-xl transition-all active:scale-95">Delete</button>
            </div>
          </div>
        </div>
      )}

      {/* Individual Delete Modal (Category) */}
      {categoryToDelete && (
        <div className="fixed inset-0 z-[400] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-900/90 backdrop-blur-sm" onClick={() => setCategoryToDelete(null)}></div>
          <div className="relative bg-white dark:bg-slate-900 w-full max-w-sm rounded-3xl shadow-2xl p-8 border border-red-100 dark:border-red-900/30 text-center animate-in zoom-in-95 duration-200">
            <div className="w-16 h-16 bg-red-50 dark:bg-red-900/20 text-red-500 rounded-full flex items-center justify-center text-2xl mx-auto mb-6">
              <i className="fa-solid fa-triangle-exclamation"></i>
            </div>
            <h3 className="text-xl font-black mb-2 dark:text-white transition-colors">Delete Category?</h3>
            <p className="text-slate-500 dark:text-slate-400 text-sm mb-8 leading-relaxed">
              Deleting <span className="font-bold text-slate-800 dark:text-slate-200">"{categoryToDelete.name}"</span> will remove it from the store navigation.
            </p>
            <div className="flex gap-3">
              <button onClick={() => setCategoryToDelete(null)} className="flex-1 py-3 px-4 border-2 border-slate-100 text-sm font-bold rounded-xl text-slate-500 dark:border-slate-800 transition-colors">Cancel</button>
              <button onClick={() => { onUpdateSettings({ ...settings, categories: settings.categories.filter(c => c.id !== categoryToDelete.id) }); setCategoryToDelete(null); }} className="flex-1 py-3 px-4 bg-red-500 hover:bg-red-600 text-white text-sm font-bold rounded-xl">Delete</button>
            </div>
          </div>
        </div>
      )}

      {/* API Config Modal */}
      {editingPayment && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-900/80 backdrop-blur-sm" onClick={() => setEditingPayment(null)}></div>
          <div className="relative bg-white dark:bg-slate-900 w-full max-w-xl rounded-3xl shadow-2xl p-8 border border-sky-200 dark:border-slate-700 animate-in zoom-in-95">
             <h3 className="text-2xl font-black mb-6 dark:text-white transition-colors">API Configuration</h3>
             <form onSubmit={handleSavePayment} className="space-y-5">
                <div>
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1 block">Account Label</label>
                  <input type="text" value={editingPayment.name} onChange={e => setEditingPayment({...editingPayment, name: e.target.value})} className="w-full bg-sky-50 dark:bg-slate-800 p-3 rounded-xl border border-sky-100 dark:border-slate-700 dark:text-white focus:outline-none focus:ring-2 focus:ring-sky-500 transition-colors" required />
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <label className="flex items-center space-x-3 cursor-pointer p-3 rounded-xl border border-sky-100 dark:border-slate-700 bg-sky-50 dark:bg-slate-800 transition-colors">
                    <input type="checkbox" checked={editingPayment.isAutomated} onChange={e => setEditingPayment({...editingPayment, isAutomated: e.target.checked})} className="w-4 h-4 text-sky-500 rounded focus:ring-sky-500" />
                    <span className="text-sm font-black dark:text-white uppercase tracking-tighter">Enable API Integration</span>
                  </label>
                </div>

                {editingPayment.isAutomated && (
                  <div className="space-y-4 animate-in fade-in slide-in-from-top-2 transition-colors">
                     <div className="p-4 bg-sky-500/5 rounded-2xl border border-sky-500/20 space-y-4">
                        <div>
                          <label className="text-[10px] font-black text-sky-500 uppercase block mb-1">API Public Key</label>
                          <input type="text" value={editingPayment.apiPublicKey || ''} onChange={e => setEditingPayment({...editingPayment, apiPublicKey: e.target.value})} className="w-full bg-white dark:bg-slate-900 p-2 rounded-lg border border-sky-100 dark:border-slate-700 font-mono text-xs dark:text-white transition-colors" placeholder="pk_live_..." />
                        </div>
                        <div>
                          <label className="text-[10px] font-black text-sky-500 uppercase block mb-1">API Secret Key</label>
                          <div className="relative">
                            <input type={showSecret ? "text" : "password"} value={editingPayment.apiSecretKey || ''} onChange={e => setEditingPayment({...editingPayment, apiSecretKey: e.target.value})} className="w-full bg-white dark:bg-slate-900 p-2 rounded-lg border border-sky-100 dark:border-slate-700 font-mono text-xs dark:text-white transition-colors" placeholder="sk_live_..." />
                            <button type="button" onClick={() => setShowSecret(!showSecret)} className="absolute right-2 top-1.5 text-slate-300 hover:text-sky-500 transition-colors"><i className={`fa-solid ${showSecret ? 'fa-eye-slash' : 'fa-eye'}`}></i></button>
                          </div>
                        </div>
                        <div>
                          <label className="text-[10px] font-black text-sky-500 uppercase block mb-1">Merchant ID</label>
                          <input type="text" value={editingPayment.merchantId || ''} onChange={e => setEditingPayment({...editingPayment, merchantId: e.target.value})} className="w-full bg-white dark:bg-slate-900 p-2 rounded-lg border border-sky-100 dark:border-slate-700 font-mono text-xs dark:text-white transition-colors" placeholder="MER-..." />
                        </div>

                        <div className="pt-2">
                           <button 
                            type="button" 
                            onClick={testApiConnection}
                            disabled={isTestingApi}
                            className="w-full py-2 bg-slate-900 dark:bg-slate-950 text-white text-[10px] font-black rounded-lg hover:bg-black transition-all flex items-center justify-center space-x-2 active:scale-95"
                           >
                             {isTestingApi ? <i className="fa-solid fa-spinner animate-spin"></i> : <i className="fa-solid fa-vial"></i>}
                             <span>{isTestingApi ? 'TESTING...' : 'RUN CONNECTIVITY TEST'}</span>
                           </button>
                           {apiTestResult && (
                             <p className={`mt-2 text-[10px] font-bold text-center ${apiTestResult.includes('Stable') ? 'text-green-500' : 'text-red-500'}`}>
                               {apiTestResult}
                             </p>
                           )}
                        </div>
                     </div>
                  </div>
                )}

                <div className="flex justify-end space-x-3 pt-6">
                  <button type="button" onClick={() => setEditingPayment(null)} className="px-6 py-2 text-slate-400 font-bold uppercase tracking-widest text-xs hover:text-slate-600 dark:hover:text-slate-300 transition-colors">Cancel</button>
                  <button type="submit" className="px-8 py-3 bg-sky-500 text-white font-black rounded-xl shadow-lg shadow-sky-100 dark:shadow-none active:scale-95 transition-all">Save Changes</button>
                </div>
             </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminDashboard;

import React, { useState, useRef } from 'react';
import { Product, Category, SiteSettings, AdminUser, PaymentMethod } from '../types';
import { paymentService } from '../services/paymentService';

interface AdminDashboardProps {
  products: Product[];
  settings: SiteSettings;
  admins: AdminUser[];
  onUpdateProducts: (newProducts: Product[]) => void;
  onUpdateSettings: (newSettings: SiteSettings) => void;
  onUpdateAdmins: (newAdmins: AdminUser[]) => void;
  onLogout: () => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ 
  products, settings, admins, onUpdateProducts, onUpdateSettings, onUpdateAdmins, onLogout 
}) => {
  const [activeTab, setActiveTab] = useState<'products' | 'categories' | 'settings' | 'admins' | 'payments'>('products');
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [editingCategory, setEditingCategory] = useState<Category | null>(null);
  const [editingPayment, setEditingPayment] = useState<PaymentMethod | null>(null);
  const [productToDelete, setProductToDelete] = useState<Product | null>(null);
  const [categoryToDelete, setCategoryToDelete] = useState<Category | null>(null);
  const [showCreateForm, setShowCreateForm] = useState(false);
  const [showCategoryForm, setShowCategoryForm] = useState(false);
  const [isTestingApi, setIsTestingApi] = useState(false);
  const [apiTestResult, setApiTestResult] = useState<string | null>(null);
  const [showSecret, setShowSecret] = useState(false);

  // Bulk Action State
  const [selectedProductIds, setSelectedProductIds] = useState<string[]>([]);
  const [showBulkDeleteConfirm, setShowBulkDeleteConfirm] = useState(false);
  const [showGlobalActionConfirm, setShowGlobalActionConfirm] = useState<'hide' | 'show' | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const editFileInputRef = useRef<HTMLInputElement>(null);

  // Form states
  const [newProduct, setNewProduct] = useState({
    name: '', description: '', price: '', category: settings.categories[0]?.id || '',
    stock: '', image: '', features: '', secretContent: ''
  });

  const [newCategory, setNewCategory] = useState({ name: '', icon: 'fa-box' });

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>, isEdit = false) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64 = reader.result as string;
        if (isEdit && editingProduct) setEditingProduct({ ...editingProduct, image: base64 });
        else setNewProduct({ ...newProduct, image: base64 });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleCreateProduct = (e: React.FormEvent) => {
    e.preventDefault();
    const product: Product = {
      id: Date.now().toString(),
      name: newProduct.name,
      description: newProduct.description,
      price: parseFloat(newProduct.price),
      category: newProduct.category,
      stock: parseInt(newProduct.stock),
      rating: 5.0,
      image: newProduct.image || 'https://picsum.photos/seed/tool/400/300',
      features: newProduct.features.split(',').map(f => f.trim()).filter(f => f !== ''),
      isVisible: true,
      secretContent: newProduct.secretContent
    };
    onUpdateProducts([product, ...products]);
    setShowCreateForm(false);
    setNewProduct({ name: '', description: '', price: '', category: settings.categories[0]?.id || '', stock: '', image: '', features: '', secretContent: '' });
  };

  const handleSaveProductEdit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingProduct) return;
    onUpdateProducts(products.map(p => p.id === editingProduct.id ? editingProduct : p));
    setEditingProduct(null);
  };

  const handleCreateCategory = (e: React.FormEvent) => {
    e.preventDefault();
    const cat: Category = {
      id: newCategory.name.toLowerCase().replace(/\s+/g, '-'),
      name: newCategory.name,
      icon: newCategory.icon
    };
    onUpdateSettings({ ...settings, categories: [...settings.categories, cat] });
    setShowCategoryForm(false);
    setNewCategory({ name: '', icon: 'fa-box' });
  };

  // Bulk & Global Actions
  const toggleSelectAll = () => {
    if (selectedProductIds.length === products.length) setSelectedProductIds([]);
    else setSelectedProductIds(products.map(p => p.id));
  };

  const toggleSelectProduct = (id: string) => {
    setSelectedProductIds(prev => prev.includes(id) ? prev.filter(pId => pId !== id) : [...prev, id]);
  };

  const bulkDelete = () => {
    onUpdateProducts(products.filter(p => !selectedProductIds.includes(p.id)));
    setSelectedProductIds([]);
    setShowBulkDeleteConfirm(false);
  };

  const bulkToggleVisibility = (visible: boolean) => {
    onUpdateProducts(products.map(p => selectedProductIds.includes(p.id) ? { ...p, isVisible: visible } : p));
    setSelectedProductIds([]);
  };

  const handleGlobalVisibility = (visible: boolean) => {
    onUpdateProducts(products.map(p => ({ ...p, isVisible: visible })));
    setShowGlobalActionConfirm(null);
  };

  return (
    <div className="flex flex-col md:flex-row min-h-[80vh] bg-white dark:bg-slate-900 rounded-3xl border border-sky-100 dark:border-slate-800 overflow-hidden shadow-xl mb-12 transition-colors">
      <div className="w-full md:w-64 bg-slate-900 text-white p-8 shrink-0">
        <h2 className="text-xl font-black mb-10 flex items-center space-x-2">
          <span className="bg-sky-500 p-1.5 rounded-lg"><i className="fa-solid fa-shield-halved"></i></span>
          <span>NETTOOLZ Admin</span>
        </h2>
        <nav className="space-y-2">
          <button onClick={() => setActiveTab('products')} className={`w-full text-left px-4 py-3 rounded-xl font-bold flex items-center space-x-3 transition-colors ${activeTab === 'products' ? 'bg-sky-500 text-white shadow-lg shadow-sky-500/20' : 'text-slate-400 hover:bg-slate-800'}`}>
            <i className="fa-solid fa-box"></i><span>Inventory</span>
          </button>
