            <p className="text-slate-500 dark:text-slate-400 text-sm mb-8">Update visibility of {products.length} items.</p>
            <div className="flex gap-3">
              <button onClick={() => setShowGlobalActionConfirm(null)} className="flex-1 py-3 px-4 border-2 border-slate-100 text-sm font-bold rounded-xl text-slate-500">Cancel</button>
              <button onClick={() => handleGlobalVisibility(showGlobalActionConfirm === 'show')} className={`flex-1 py-3 px-4 ${showGlobalActionConfirm === 'show' ? 'bg-green-500 hover:bg-green-600' : 'bg-slate-800 hover:bg-black'} text-white text-sm font-bold rounded-xl shadow-lg transition-all active:scale-95`}>Confirm</button>
            </div>
          </div>
        </div>
      )}

      {showBulkDeleteConfirm && (
        <div className="fixed inset-0 z-[500] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-900/90 backdrop-blur-sm" onClick={() => setShowBulkDeleteConfirm(false)}></div>
          <div className="relative bg-white dark:bg-slate-900 w-full max-w-sm rounded-3xl shadow-2xl p-8 border border-red-100 text-center animate-in zoom-in-95">
            <div className="w-16 h-16 bg-red-50 text-red-500 rounded-full flex items-center justify-center text-2xl mx-auto mb-6"><i className="fa-solid fa-trash"></i></div>
            <h3 className="text-xl font-black mb-2 dark:text-white">Delete {selectedProductIds.length} Items?</h3>
            <p className="text-slate-500 text-sm mb-8">This action is permanent and cannot be reversed.</p>
            <div className="flex gap-3">
              <button onClick={() => setShowBulkDeleteConfirm(false)} className="flex-1 py-3 px-4 border-2 border-slate-100 text-sm font-bold rounded-xl text-slate-500">Cancel</button>
              <button onClick={bulkDelete} className="flex-1 py-3 px-4 bg-red-500 text-white text-sm font-bold rounded-xl shadow-lg">Delete All</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

