    setCurrentUser(user);
    await dbService.saveUser(user);
    localStorage.setItem('nettoolz_logged_user_email', user.email);
    setCurrentView('profile');
  };

  const handleFundSuccess = async (amount: number) => {
    if (!currentUser) return;
    const updatedUser = {
      ...currentUser,
      balance: currentUser.balance + amount
    };
    setUsers(prev => prev.map(u => u.email === updatedUser.email ? updatedUser : u));
    setCurrentUser(updatedUser);
    await dbService.saveUser(updatedUser);
  };

  const addToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      return [...prev, { ...product, quantity: 1 }];
    });
  };

  const handleCheckout = async () => {
    if (!currentUser) { setCurrentView('profile'); setIsCartOpen(false); return; }
    const total = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0);
    if (currentUser.balance < total) { alert('Insufficient balance.'); setCurrentView('fund_wallet'); setIsCartOpen(false); return; }

    setIsProcessingCheckout(true);
    await new Promise(resolve => setTimeout(resolve, 1500));
    const newOrders: UserOrder[] = cart.map(item => ({ id: Date.now().toString() + Math.random(), productId: item.id, productName: item.name, content: item.secretContent || 'Processing...', price: item.price, timestamp: Date.now() }));
    const updatedUser = { ...currentUser, balance: currentUser.balance - total, orders: [...currentUser.orders, ...newOrders] };

    setUsers(prev => prev.map(u => u.email === updatedUser.email ? updatedUser : u));
    setCurrentUser(updatedUser);
    await dbService.saveUser(updatedUser);

    setCart([]); 
    setIsCartOpen(false); 
    setIsProcessingCheckout(false); 
    setCurrentView('profile');
    alert('Purchase confirmed!');
  };

  if (isLoadingDB) {
    return (
      <div className="h-screen w-screen flex flex-col items-center justify-center bg-white dark:bg-slate-950">
        <div className="relative w-24 h-24 mb-6">
          <div className="absolute inset-0 border-4 border-sky-100 dark:border-slate-800 rounded-full"></div>
          <div className="absolute inset-0 border-4 border-sky-500 rounded-full border-t-transparent animate-spin"></div>
          <div className="absolute inset-0 flex items-center justify-center text-sky-500">
            <i className="fa-solid fa-database text-2xl"></i>
          </div>
        </div>
        <h1 className="text-xl font-black text-slate-800 dark:text-white uppercase tracking-widest">Initializing Secure DB</h1>
        <p className="text-slate-400 dark:text-slate-500 text-sm mt-2 font-medium">Encrypting and loading digital assets...</p>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex flex-col bg-sky-50 dark:bg-slate-950 transition-colors">
      <Navbar 
        cartCount={cart.reduce((acc, item) => acc + item.quantity, 0)} 
        isDarkMode={isDarkMode} 
        logoUrl={settings.logoUrl}
        currentUserEmail={currentUser?.email}
        onNavigate={setCurrentView} 
        onOpenCart={() => setIsCartOpen(true)} 
        onToggleTheme={() => { setIsDarkMode(!isDarkMode); document.documentElement.classList.toggle('dark'); }} 
      />
      <main className="flex-1 max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 w-full">
        {currentView === 'home' && (
          <div className="space-y-16 py-12">
            <section className="relative px-6 py-20 bg-white dark:bg-slate-900 rounded-3xl border border-sky-100 dark:border-slate-800 overflow-hidden shadow-sm">
              <div className="relative z-10 text-center max-w-3xl mx-auto">
                <span className="inline-block px-4 py-2 bg-sky-100 dark:bg-sky-900/30 text-sky-600 dark:text-sky-400 rounded-full text-xs font-black uppercase mb-6 tracking-widest">Premium Digital Tools</span>
                <h1 className="text-5xl sm:text-6xl font-black text-slate-900 dark:text-white leading-tight mb-6">NET<span className="text-sky-500">TOOLZ</span> Enterprise</h1>
                <p className="text-lg text-slate-500 dark:text-slate-400 mb-10 leading-relaxed">Secure, automated access to high-performance proxies and VPNs.</p>
                <button onClick={() => setCurrentView('category')} className="bg-sky-500 hover:bg-sky-600 text-white font-black px-10 py-4 rounded-2xl shadow-xl transition-all active:scale-95">Enter Catalog</button>
              </div>
            </section>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-8">
              {products.filter(p => p.isVisible).slice(0, 3).map(p => <ProductCard key={p.id} product={p} onAddToCart={addToCart} onViewDetails={(p) => { setSelectedProduct(p); setCurrentView('product'); }} />)}
            </div>
          </div>
        )}

        {currentView === 'category' && (
          <div className="py-12 flex flex-col md:flex-row gap-12">
            <div className="w-full md:w-64 space-y-4">
              <h3 className="text-lg font-black dark:text-white">Categories</h3>
              <div className="space-y-2">
                <button onClick={() => setSelectedCategory(null)} className={`w-full text-left px-4 py-2 rounded-xl transition-all ${!selectedCategory ? 'bg-sky-500 text-white font-bold shadow-lg shadow-sky-100' : 'bg-white dark:bg-slate-900 text-slate-400 hover:bg-sky-50 dark:hover:bg-slate-800'}`}>All Assets</button>
                {settings.categories.map(cat => <button key={cat.id} onClick={() => setSelectedCategory(cat.id)} className={`w-full text-left px-4 py-2 rounded-xl transition-all ${selectedCategory === cat.id ? 'bg-sky-500 text-white font-bold shadow-lg shadow-sky-100' : 'bg-white dark:bg-slate-900 text-slate-400 hover:bg-sky-50 dark:hover:bg-slate-800'}`}>{cat.name}</button>)}
              </div>
            </div>
            <div className="flex-1 grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
              {products.filter(p => p.isVisible && (!selectedCategory || p.category === selectedCategory)).map(p => <ProductCard key={p.id} product={p} onAddToCart={addToCart} onViewDetails={(p) => { setSelectedProduct(p); setCurrentView('product'); }} />)}
            </div>
          </div>
        )}

        {currentView === 'product' && selectedProduct && (
          <div className="py-12 max-w-5xl mx-auto">
            <div className="bg-white dark:bg-slate-900 rounded-3xl p-8 border border-sky-100 dark:border-slate-800 flex flex-col md:flex-row gap-12">
              <div className="flex-1 rounded-2xl overflow-hidden shadow-lg bg-sky-50 dark:bg-slate-800 min-h-[400px]">
                <img src={selectedProduct.image} className="w-full h-full object-cover" />
              </div>
              <div className="flex-1 space-y-6">
                <h1 className="text-4xl font-black dark:text-white leading-tight">{selectedProduct.name}</h1>
                <p className="text-3xl font-black text-sky-500">₦{selectedProduct.price.toLocaleString()}</p>
                <div className="space-y-4">
                  <p className="text-slate-500 dark:text-slate-400 leading-relaxed">{selectedProduct.description}</p>
                  <div className="flex flex-wrap gap-2 pt-4">
                    {selectedProduct.features.map((f, i) => (
                      <span key={i} className="bg-sky-50 dark:bg-slate-800 text-sky-600 dark:text-sky-400 text-[10px] font-black uppercase px-2 py-1 rounded-lg">
                        <i className="fa-solid fa-check mr-1"></i> {f}
                      </span>
                    ))}
                  </div>
                </div>
                <button onClick={() => addToCart(selectedProduct)} className="w-full bg-sky-500 text-white font-black py-4 rounded-xl shadow-lg transition-all active:scale-95 mt-6">Add to Cart</button>
              </div>
            </div>
          </div>
        )}

        {currentView === 'profile' && (
          currentUser ? (
            <UserProfile user={currentUser} settings={settings} onFundWallet={() => setCurrentView('fund_wallet')} onLogout={() => { setCurrentUser(null); localStorage.removeItem('nettoolz_logged_user_email'); setCurrentView('home'); }} />
          ) : (
            <UserAuth users={users} onAuth={handleAuth} onCancel={() => setCurrentView('home')} />
          )
        )}

        {currentView === 'fund_wallet' && <WalletFunding settings={settings} onBack={() => setCurrentView('profile')} onFundSuccess={handleFundSuccess} />}
        {currentView === 'admin_dashboard' && isAdminLoggedIn && <AdminDashboard products={products} settings={settings} admins={admins} onUpdateProducts={handleUpdateProducts} onUpdateSettings={handleUpdateSettings} onUpdateAdmins={handleUpdateAdmins} onLogout={() => { setIsAdminLoggedIn(false); localStorage.removeItem('nettoolz_admin_logged'); setCurrentView('home'); }} />}
        {currentView === 'admin_login' && <AdminLogin onLogin={(s) => { if(s) { setIsAdminLoggedIn(true); localStorage.setItem('nettoolz_admin_logged', 'true'); setCurrentView('admin_dashboard'); } }} onCancel={() => setCurrentView('home')} />}
      </main>

      {/* Cart Drawer... */}
      {isCartOpen && (
        <div className="fixed inset-0 z-[110] flex justify-end">
          <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={() => setIsCartOpen(false)}></div>
          <div className="relative w-full max-w-md bg-white dark:bg-slate-900 h-full p-8 flex flex-col shadow-2xl animate-in slide-in-from-right duration-300">
            <h2 className="text-2xl font-black dark:text-white mb-8">Cart</h2>
            <div className="flex-1 overflow-y-auto space-y-4">
              {cart.map(item => (
                <div key={item.id} className="flex gap-4 p-4 bg-sky-50 dark:bg-slate-800 rounded-xl">
                  <div className="flex-1">
                    <p className="font-bold dark:text-white">{item.name}</p>
                    <p className="text-sky-500 font-bold">₦{item.price.toLocaleString()} x {item.quantity}</p>
                  </div>
                  <button onClick={() => setCart(cart.filter(i => i.id !== item.id))} className="text-red-400 hover:text-red-600 transition-colors"><i className="fa-solid fa-trash"></i></button>
                </div>
              ))}
              {cart.length === 0 && (
                <div className="text-center py-20 text-slate-400">
                  <i className="fa-solid fa-cart-arrow-down text-4xl mb-4"></i>
                  <p className="font-bold">Your cart is empty.</p>
                </div>
              )}
            </div>
            <div className="pt-8 border-t dark:border-slate-800 mt-6">
              <div className="flex justify-between text-2xl font-black mb-6 dark:text-white"><span>Total</span><span className="text-sky-500">₦{cart.reduce((a, i) => a + (i.price * i.quantity), 0).toLocaleString()}</span></div>
              <button onClick={handleCheckout} disabled={isProcessingCheckout || cart.length === 0} className="w-full bg-sky-500 text-white font-black py-4 rounded-xl hover:bg-sky-600 transition-all active:scale-95 disabled:bg-slate-300 disabled:cursor-not-allowed">{isProcessingCheckout ? 'Processing...' : 'Complete Checkout'}</button>
            </div>
          </div>
        </div>
      )}

      <footer className="bg-white dark:bg-slate-900 border-t py-12 text-center transition-colors">
        <p className="text-slate-400 text-xs font-black uppercase tracking-widest">© 2024 NETTOOLZ Enterprise. Database Secured.</p>
        <button onClick={() => setCurrentView('admin_login')} className="mt-8 text-[10px] text-slate-300 hover:text-sky-500 font-black tracking-widest transition-colors">ADMIN PORTAL</button>
      </footer>
      <GeminiAssistant />
    </div>
  );
};

export default App;

import React, { useState, useRef } from 'react';
import { Product, Category, SiteSettings, AdminUser, PaymentMethod } from '../types';
import { paymentService } from '../services/paymentService';
import { GoogleGenAI } from "@google/genai";

interface AdminDashboardProps {
  products: Product[];
  settings: SiteSettings;
  admins: AdminUser[];
  onUpdateProducts: (newProducts: Product[]) => void;
  onUpdateSettings: (newSettings: SiteSettings) => void;
  onUpdateAdmins: (newAdmins: AdminUser[]) => void;
  onLogout: () => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ 
  products, settings, admins, onUpdateProducts, onUpdateSettings, onUpdateAdmins, onLogout 
}) => {
  const [activeTab, setActiveTab] = useState<'products' | 'categories' | 'settings' | 'admins' | 'payments'>('products');
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [editingCategory, setEditingCategory] = useState<Category | null>(null);
  const [editingPayment, setEditingPayment] = useState<PaymentMethod | null>(null);
  const [productToDelete, setProductToDelete] = useState<Product | null>(null);
  const [categoryToDelete, setCategoryToDelete] = useState<Category | null>(null);
  const [adminToDelete, setAdminToDelete] = useState<AdminUser | null>(null);
  const [showCreateForm, setShowCreateForm] = useState(false);
  const [showCategoryForm, setShowCategoryForm] = useState(false);
  const [showAdminForm, setShowAdminForm] = useState(false);
  const [isTestingApi, setIsTestingApi] = useState(false);
  const [apiTestResult, setApiTestResult] = useState<string | null>(null);
  const [showSecret, setShowSecret] = useState(false);

  // Logo Generation State
  const [isGeneratingLogo, setIsGeneratingLogo] = useState(false);
  const [tempLogoUrl, setTempLogoUrl] = useState<string | null>(null);

  // Bulk Action State
  const [selectedProductIds, setSelectedProductIds] = useState<string[]>([]);
  const [showBulkDeleteConfirm, setShowBulkDeleteConfirm] = useState(false);
  const [showGlobalActionConfirm, setShowGlobalActionConfirm] = useState<'hide' | 'show' | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const editFileInputRef = useRef<HTMLInputElement>(null);

  // Form states
  const [newProduct, setNewProduct] = useState({
    name: '', description: '', price: '', category: settings.categories[0]?.id || '',
    stock: '', image: '', features: '', secretContent: ''
  });

  const [newCategory, setNewCategory] = useState({ name: '', icon: 'fa-box' });
  const [newAdmin, setNewAdmin] = useState({ username: '', role: 'editor' as 'super' | 'editor' });

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>, isEdit = false) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64 = reader.result as string;
        if (isEdit && editingProduct) setEditingProduct({ ...editingProduct, image: base64 });
        else setNewProduct({ ...newProduct, image: base64 });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleCreateProduct = (e: React.FormEvent) => {
    e.preventDefault();
    const product: Product = {
      id: Date.now().toString(),
      name: newProduct.name,
      description: newProduct.description,
      price: parseFloat(newProduct.price),
      category: newProduct.category,
      stock: parseInt(newProduct.stock),
      rating: 5.0,
      image: newProduct.image || 'https://picsum.photos/seed/tool/400/300',
      features: newProduct.features.split(',').map(f => f.trim()).filter(f => f !== ''),
      isVisible: true,
      secretContent: newProduct.secretContent
    };
    onUpdateProducts([product, ...products]);
    setShowCreateForm(false);
    setNewProduct({ name: '', description: '', price: '', category: settings.categories[0]?.id || '', stock: '', image: '', features: '', secretContent: '' });
  };

  const handleSaveProductEdit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingProduct) return;
    onUpdateProducts(products.map(p => p.id === editingProduct.id ? editingProduct : p));
    setEditingProduct(null);
  };

  const handleCreateCategory = (e: React.FormEvent) => {
    e.preventDefault();
    const cat: Category = {
      id: newCategory.name.toLowerCase().replace(/\s+/g, '-'),
      name: newCategory.name,
      icon: newCategory.icon
    };
    onUpdateSettings({ ...settings, categories: [...settings.categories, cat] });
    setShowCategoryForm(false);
    setNewCategory({ name: '', icon: 'fa-box' });
  };

  const handleSaveCategoryEdit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingCategory) return;
    onUpdateSettings({
      ...settings,
      categories: settings.categories.map(c => c.id === editingCategory.id ? editingCategory : c)
    });
    setEditingCategory(null);
  };

  const handleCreateAdmin = (e: React.FormEvent) => {
    e.preventDefault();
    const admin: AdminUser = {
      id: Date.now().toString(),
      username: newAdmin.username,
      role: newAdmin.role
    };
    onUpdateAdmins([...admins, admin]);
    setShowAdminForm(false);
    setNewAdmin({ username: '', role: 'editor' });
  };

  const testApiConnection = async () => {
    if (!editingPayment) return;
    setIsTestingApi(true);
    setApiTestResult(null);

    const res = await paymentService.initiateAutomatedPayment(
      'test', 
      1000, 
      { 
        publicKey: editingPayment.apiPublicKey, 
        merchantId: editingPayment.merchantId,
        type: editingPayment.type
      }
    );

    setApiTestResult(res.success ? "Connection Stable: API responded with 200 OK." : `Error: ${res.message}`);
    setIsTestingApi(false);
  };

  const handleSavePayment = (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingPayment) return;
    const existingIndex = settings.paymentMethods.findIndex(m => m.id === editingPayment.id);
    let newMethods;
    if (existingIndex > -1) {
      newMethods = settings.paymentMethods.map(m => m.id === editingPayment.id ? editingPayment : m);
    } else {
      newMethods = [...settings.paymentMethods, editingPayment];
    }
    onUpdateSettings({ ...settings, paymentMethods: newMethods });
    setEditingPayment(null);
    setApiTestResult(null);
  };

  const generateLogo = async () => {
    setIsGeneratingLogo(true);
    setTempLogoUrl(null);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `A modern and professional logo for "NETTOOLZ", an e-commerce platform for high-quality digital tools, networking software, and technical logs. The logo should feature a sleek sky-blue aesthetic, incorporate subtle tech or networking elements like circuit paths or data nodes, and have a minimalist, high-end feel. White background. Clean vector style.`;

      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: { parts: [{ text: prompt }] },
      });

      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData) {
          const base64 = `data:image/png;base64,${part.inlineData.data}`;
          setTempLogoUrl(base64);
          break;
        }
      }
    } catch (error) {
      console.error("Logo generation failed:", error);
      alert("Failed to generate logo. Ensure your API key is correctly configured.");
    } finally {
      setIsGeneratingLogo(false);
    }
  };

  const applyLogo = () => {
    if (tempLogoUrl) {
      onUpdateSettings({ ...settings, logoUrl: tempLogoUrl });
      setTempLogoUrl(null);
      alert("Brand logo updated successfully!");
    }
  };

  // Bulk & Global Actions
  const toggleSelectAll = () => {
    if (selectedProductIds.length === products.length) setSelectedProductIds([]);
    else setSelectedProductIds(products.map(p => p.id));
  };

  const toggleSelectProduct = (id: string) => {
    setSelectedProductIds(prev => prev.includes(id) ? prev.filter(pId => pId !== id) : [...prev, id]);
  };

  const bulkDelete = () => {
    onUpdateProducts(products.filter(p => !selectedProductIds.includes(p.id)));
    setSelectedProductIds([]);
    setShowBulkDeleteConfirm(false);
  };

  const bulkToggleVisibility = (visible: boolean) => {
    onUpdateProducts(products.map(p => selectedProductIds.includes(p.id) ? { ...p, isVisible: visible } : p));
    setSelectedProductIds([]);
  };

  const handleGlobalVisibility = (visible: boolean) => {
    onUpdateProducts(products.map(p => ({ ...p, isVisible: visible })));
    setShowGlobalActionConfirm(null);
  };

  return (
    <div className="flex flex-col md:flex-row min-h-[80vh] bg-white dark:bg-slate-900 rounded-3xl border border-sky-100 dark:border-slate-800 overflow-hidden shadow-xl mb-12 transition-colors">
      <div className="w-full md:w-64 bg-slate-900 text-white p-8 shrink-0">
        <h2 className="text-xl font-black mb-10 flex items-center space-x-2">
          <span className="bg-sky-500 p-1.5 rounded-lg"><i className="fa-solid fa-shield-halved"></i></span>
          <span>NETTOOLZ Admin</span>
        </h2>
        <nav className="space-y-2">
          <button onClick={() => setActiveTab('products')} className={`w-full text-left px-4 py-3 rounded-xl font-bold flex items-center space-x-3 transition-colors ${activeTab === 'products' ? 'bg-sky-500 text-white shadow-lg shadow-sky-500/20' : 'text-slate-400 hover:bg-slate-800'}`}>
            <i className="fa-solid fa-box"></i><span>Inventory</span>
          </button>
          <button onClick={() => setActiveTab('categories')} className={`w-full text-left px-4 py-3 rounded-xl font-bold flex items-center space-x-3 transition-colors ${activeTab === 'categories' ? 'bg-sky-500 text-white shadow-lg shadow-sky-500/20' : 'text-slate-400 hover:bg-slate-800'}`}>
            <i className="fa-solid fa-tags"></i><span>Categories</span>
          </button>
          <button onClick={() => setActiveTab('admins')} className={`w-full text-left px-4 py-3 rounded-xl font-bold flex items-center space-x-3 transition-colors ${activeTab === 'admins' ? 'bg-sky-500 text-white shadow-lg shadow-sky-500/20' : 'text-slate-400 hover:bg-slate-800'}`}>
            <i className="fa-solid fa-user-shield"></i><span>Staff</span>
          </button>
          <button onClick={() => setActiveTab('payments')} className={`w-full text-left px-4 py-3 rounded-xl font-bold flex items-center space-x-3 transition-colors ${activeTab === 'payments' ? 'bg-sky-500 text-white shadow-lg shadow-sky-500/20' : 'text-slate-400 hover:bg-slate-800'}`}>
            <i className="fa-solid fa-plug"></i><span>API Config</span>
          </button>
          <button onClick={() => setActiveTab('settings')} className={`w-full text-left px-4 py-3 rounded-xl font-bold flex items-center space-x-3 transition-colors ${activeTab === 'settings' ? 'bg-sky-500 text-white shadow-lg shadow-sky-500/20' : 'text-slate-400 hover:bg-slate-800'}`}>
            <i className="fa-solid fa-gears"></i><span>General</span>
          </button>
        </nav>
        <button onClick={onLogout} className="mt-20 w-full text-left px-4 py-3 text-red-400 font-bold hover:bg-red-500/10 rounded-xl transition-colors">
          <i className="fa-solid fa-power-off mr-2"></i>Logout
        </button>
      </div>

      <div className="flex-1 p-8 bg-sky-50/20 dark:bg-slate-900/40 overflow-y-auto">
        <header className="flex flex-col sm:flex-row justify-between items-start sm:items-center mb-10 gap-4">
          <div>
            <h3 className="text-3xl font-black dark:text-white capitalize tracking-tight">{activeTab}</h3>
            <p className="text-xs text-slate-400 font-bold uppercase tracking-widest mt-1">Management Portal</p>
          </div>
          <div className="flex items-center space-x-4">
            {activeTab === 'products' && (
              <button 
                onClick={() => setShowCreateForm(!showCreateForm)}
                className={`flex items-center space-x-2 font-black px-6 py-2.5 rounded-xl shadow-lg transition-all active:scale-95 ${showCreateForm ? 'bg-slate-800 text-white' : 'bg-sky-500 text-white'}`}
              >
                <i className={`fa-solid ${showCreateForm ? 'fa-xmark' : 'fa-plus'}`}></i>
                <span>{showCreateForm ? 'Cancel' : 'Add Product'}</span>
              </button>
            )}
            {activeTab === 'categories' && (
              <button onClick={() => setShowCategoryForm(!showCategoryForm)} className="bg-sky-500 text-white font-black px-6 py-2.5 rounded-xl shadow-lg transition-all active:scale-95">
                <i className="fa-solid fa-plus mr-2"></i>New Category
              </button>
            )}
            {activeTab === 'admins' && (
              <button onClick={() => setShowAdminForm(!showAdminForm)} className="bg-sky-500 text-white font-black px-6 py-2.5 rounded-xl shadow-lg transition-all active:scale-95">
                <i className="fa-solid fa-user-plus mr-2"></i>Add Staff
              </button>
            )}
          </div>
        </header>

        {activeTab === 'products' && (
          <div className="space-y-6 animate-in fade-in duration-300">
            {showCreateForm && (
               <form onSubmit={handleCreateProduct} className="bg-white dark:bg-slate-800 p-8 rounded-3xl border border-sky-100 dark:border-slate-700 shadow-xl space-y-4 animate-in slide-in-from-top-4">
                 <h4 className="text-xl font-black dark:text-white mb-4">New Digital Asset</h4>
